use crate::mcp::fs_guard::FsGuard;
use crate::mcp::tools::ToolRuntime;
use serde_json::{json, Value};
use std::io::{self, BufRead, Write};

const DEFAULT_PROTOCOL_VERSION: &str = "2024-11-05";

pub fn run_stdio() -> Result<(), String> {
    let guard = FsGuard::from_env_or_cwd()?;
    let stdin = io::stdin();
    let mut stdout = io::stdout();
    let mut runtime = ToolRuntime::new(guard);

    for line in stdin.lock().lines() {
        let line = line.map_err(|e| e.to_string())?;
        if line.trim().is_empty() {
            continue;
        }
        let response = match serde_json::from_str::<Value>(&line) {
            Ok(value) => handle_json_value(&mut runtime, value),
            Err(err) => Some(error_response(
                Value::Null,
                -32700,
                &format!("parse error: {err}"),
            )),
        };
        if let Some(response) = response {
            let text = serde_json::to_string(&response).map_err(|e| e.to_string())?;
            stdout
                .write_all(text.as_bytes())
                .and_then(|_| stdout.write_all(b"\n"))
                .and_then(|_| stdout.flush())
                .map_err(|e| e.to_string())?;
        }
    }
    Ok(())
}

pub fn handle_json_value(runtime: &mut ToolRuntime, message: Value) -> Option<Value> {
    let id = message.get("id").cloned();
    let method = message.get("method").and_then(Value::as_str);

    let Some(method) = method else {
        return id.map(|id| error_response(id, -32600, "missing method"));
    };

    if id.is_none() {
        return None;
    }
    let id = id.unwrap();

    match method {
        "initialize" => Some(success_response(id, initialize_result(&message))),
        "tools/list" => Some(success_response(id, runtime.tools_list())),
        "tools/call" => {
            let params = message.get("params").cloned().unwrap_or_else(|| json!({}));
            let name = params.get("name").and_then(Value::as_str);
            let Some(name) = name else {
                return Some(error_response(
                    id,
                    -32602,
                    "tools/call params.name is required",
                ));
            };
            let arguments = params
                .get("arguments")
                .cloned()
                .unwrap_or_else(|| json!({}));
            match runtime.call_tool(name, arguments) {
                Ok(value) => Some(success_response(id, tool_result(value))),
                Err(err) => Some(success_response(id, tool_error_result(err))),
            }
        }
        "ping" => Some(success_response(id, json!({}))),
        _ => Some(error_response(
            id,
            -32601,
            &format!("method not found: {method}"),
        )),
    }
}

fn initialize_result(message: &Value) -> Value {
    let protocol_version = message
        .get("params")
        .and_then(|p| p.get("protocolVersion"))
        .and_then(Value::as_str)
        .unwrap_or(DEFAULT_PROTOCOL_VERSION);

    json!({
        "protocolVersion": protocol_version,
        "capabilities": {
            "tools": {
                "listChanged": false
            }
        },
        "serverInfo": {
            "name": "rhwp-mcp",
            "version": env!("CARGO_PKG_VERSION")
        }
    })
}

fn tool_result(value: Value) -> Value {
    let text = serde_json::to_string_pretty(&value).unwrap_or_else(|_| value.to_string());
    json!({
        "content": [
            {
                "type": "text",
                "text": text
            }
        ],
        "structuredContent": value,
        "isError": false
    })
}

fn tool_error_result(error: String) -> Value {
    json!({
        "content": [
            {
                "type": "text",
                "text": error
            }
        ],
        "isError": true
    })
}

fn success_response(id: Value, result: Value) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": result
    })
}

fn error_response(id: Value, code: i64, message: &str) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "error": {
            "code": code,
            "message": message
        }
    })
}

