    fn runtime() -> ToolRuntime {
        ToolRuntime::new(FsGuard::from_env_or_cwd().expect("fs guard"))
    }

    fn call_tool(runtime: &mut ToolRuntime, id: &str, name: &str, arguments: Value) -> Value {
        handle_json_value(
            runtime,
            json!({
                "jsonrpc": "2.0",
                "id": id,
                "method": "tools/call",
                "params": {
                    "name": name,
                    "arguments": arguments
                }
            }),
        )
        .expect("tool response")
    }

    fn call_tool_ok(runtime: &mut ToolRuntime, id: &str, name: &str, arguments: Value) -> Value {
        let response = call_tool(runtime, id, name, arguments);
        assert_eq!(
            response["result"]["isError"], false,
            "tool call failed: {response}"
        );
        response["result"]["structuredContent"].clone()
    }

    fn call_tool_error_text(
        runtime: &mut ToolRuntime,
        id: &str,
        name: &str,
        arguments: Value,
    ) -> String {
        let response = call_tool(runtime, id, name, arguments);
        assert_eq!(
            response["result"]["isError"], true,
            "tool call unexpectedly succeeded: {response}"
        );
        response["result"]["content"][0]["text"]
            .as_str()
            .expect("tool error text")
            .to_string()
    }

    fn session_id(value: &Value) -> String {
        value["session_id"]
            .as_str()
            .expect("session_id")
            .to_string()
    }

    fn decode_export(value: &Value) -> Vec<u8> {
        BASE64
            .decode(value["base64"].as_str().expect("base64 export"))
            .expect("valid base64 export")
    }

    fn semantic_template_value(value: &Value) -> Value {
        match value {
            Value::Array(items) => {
                Value::Array(items.iter().map(semantic_template_value).collect())
            }
            Value::Object(map) => {
                let mut normalized = Map::new();
                for (key, child) in map {
                    if is_volatile_template_key(key) {
                        continue;
                    }
                    normalized.insert(key.clone(), semantic_template_value(child));
                }
                Value::Object(normalized)
            }
            _ => value.clone(),
        }
    }

    fn is_volatile_template_key(key: &str) -> bool {
        key == "line_segments"
            || key == "object_layout"
            || key == "char_shape_runs"
            || key == "cell_formats"
            || key == "source_page_count"
            || key.starts_with("raw_hwp_")
    }

    fn first_value_diff(left: &Value, right: &Value, path: &str) -> Option<String> {
        match (left, right) {
            (Value::Object(left_map), Value::Object(right_map)) => {
                let mut keys = std::collections::BTreeSet::new();
                keys.extend(left_map.keys());
                keys.extend(right_map.keys());
                for key in keys {
                    let child_path = format!("{path}.{key}");
                    match (left_map.get(key), right_map.get(key)) {
                        (Some(left_child), Some(right_child)) => {
                            if let Some(diff) =
                                first_value_diff(left_child, right_child, &child_path)
                            {
                                return Some(diff);
                            }
                        }
                        (Some(left_child), None) => {
                            return Some(format!(
                                "{child_path}: extra left {}",
                                short_json(left_child)
                            ));
                        }
                        (None, Some(right_child)) => {
                            return Some(format!(
                                "{child_path}: missing left, right {}",
                                short_json(right_child)
                            ));
                        }
                        (None, None) => {}
                    }
                }
                None
            }
            (Value::Array(left_items), Value::Array(right_items)) => {
                if left_items.len() != right_items.len() {
                    return Some(format!(
                        "{path}: array length left {} right {}",
                        left_items.len(),
                        right_items.len()
                    ));
                }
                for (idx, (left_child, right_child)) in
                    left_items.iter().zip(right_items.iter()).enumerate()
                {
                    if let Some(diff) =
                        first_value_diff(left_child, right_child, &format!("{path}[{idx}]"))
                    {
                        return Some(diff);
                    }
                }
                None
            }
            _ if left == right => None,
            _ => Some(format!(
                "{path}: left {} right {}",
                short_json(left),
                short_json(right)
            )),
        }
    }

    fn short_json(value: &Value) -> String {
        let mut text = value.to_string();
        if text.len() > 240 {
            text.truncate(240);
            text.push_str("...");
        }
        text
    }

