    fn document_contains_equation_script(core: &DocumentCore, script: &str) -> bool {
        core.document
            .sections
            .iter()
            .any(|section| paragraphs_contain_equation_script(&section.paragraphs, script))
    }

    fn paragraphs_contain_equation_script(
        paragraphs: &[crate::model::paragraph::Paragraph],
        script: &str,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Equation(eq) => eq.script == script,
                Control::Table(table) => table
                    .cells
                    .iter()
                    .any(|cell| paragraphs_contain_equation_script(&cell.paragraphs, script)),
                Control::Header(header) => {
                    paragraphs_contain_equation_script(&header.paragraphs, script)
                }
                Control::Footer(footer) => {
                    paragraphs_contain_equation_script(&footer.paragraphs, script)
                }
                Control::Footnote(note) => {
                    paragraphs_contain_equation_script(&note.paragraphs, script)
                }
                Control::Endnote(note) => {
                    paragraphs_contain_equation_script(&note.paragraphs, script)
                }
                Control::HiddenComment(comment) => {
                    paragraphs_contain_equation_script(&comment.paragraphs, script)
                }
                Control::Shape(shape) => shape
                    .drawing()
                    .and_then(|drawing| drawing.text_box.as_ref())
                    .map(|text_box| {
                        paragraphs_contain_equation_script(&text_box.paragraphs, script)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

    fn document_contains_picture_transparency(core: &DocumentCore, transparency: u8) -> bool {
        core.document.sections.iter().any(|section| {
            paragraphs_contain_picture_transparency(&section.paragraphs, transparency)
        })
    }

    fn count_ole_controls(core: &DocumentCore) -> usize {
        core.document
            .sections
            .iter()
            .map(|section| count_ole_controls_in_paragraphs(&section.paragraphs))
            .sum()
    }

    fn count_ole_controls_in_paragraphs(
        paragraphs: &[crate::model::paragraph::Paragraph],
    ) -> usize {
        paragraphs
            .iter()
            .map(|para| {
                para.controls
                    .iter()
                    .map(count_ole_controls_in_control)
                    .sum::<usize>()
            })
            .sum()
    }

    fn count_ole_controls_in_control(control: &Control) -> usize {
        match control {
            Control::Shape(shape) => count_ole_controls_in_shape(shape.as_ref()),
            Control::Table(table) => table
                .cells
                .iter()
                .map(|cell| count_ole_controls_in_paragraphs(&cell.paragraphs))
                .sum(),
            Control::Header(header) => count_ole_controls_in_paragraphs(&header.paragraphs),
            Control::Footer(footer) => count_ole_controls_in_paragraphs(&footer.paragraphs),
            Control::Footnote(note) => count_ole_controls_in_paragraphs(&note.paragraphs),
            Control::Endnote(note) => count_ole_controls_in_paragraphs(&note.paragraphs),
            Control::HiddenComment(comment) => {
                count_ole_controls_in_paragraphs(&comment.paragraphs)
            }
            _ => 0,
        }
    }

    fn count_ole_controls_in_shape(shape: &ShapeObject) -> usize {
        let own = usize::from(matches!(shape, ShapeObject::Ole(_)));
        let group_children = match shape {
            ShapeObject::Group(group) => group
                .children
                .iter()
                .map(count_ole_controls_in_shape)
                .sum::<usize>(),
            _ => 0,
        };
        let nested = shape
            .drawing()
            .map(|drawing| {
                drawing
                    .text_box
                    .as_ref()
                    .map(|text_box| count_ole_controls_in_paragraphs(&text_box.paragraphs))
                    .unwrap_or(0)
                    + drawing
                        .caption
                        .as_ref()
                        .map(|caption| count_ole_controls_in_paragraphs(&caption.paragraphs))
                        .unwrap_or(0)
            })
            .unwrap_or(0);
        own + group_children + nested
    }

    fn paragraphs_contain_picture_transparency(
        paragraphs: &[crate::model::paragraph::Paragraph],
        transparency: u8,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Picture(pic) => pic.image_attr.clamped_transparency() == transparency,
                Control::Shape(shape) => match shape.as_ref() {
                    ShapeObject::Picture(pic) => {
                        pic.image_attr.clamped_transparency() == transparency
                    }
                    other => other
                        .drawing()
                        .map(|drawing| {
                            drawing
                                .text_box
                                .as_ref()
                                .map(|text_box| {
                                    paragraphs_contain_picture_transparency(
                                        &text_box.paragraphs,
                                        transparency,
                                    )
                                })
                                .unwrap_or(false)
                                || drawing
                                    .caption
                                    .as_ref()
                                    .map(|caption| {
                                        paragraphs_contain_picture_transparency(
                                            &caption.paragraphs,
                                            transparency,
                                        )
                                    })
                                    .unwrap_or(false)
                        })
                        .unwrap_or(false),
                },
                Control::Table(table) => table.cells.iter().any(|cell| {
                    paragraphs_contain_picture_transparency(&cell.paragraphs, transparency)
                }),
                Control::Header(header) => {
                    paragraphs_contain_picture_transparency(&header.paragraphs, transparency)
                }
                Control::Footer(footer) => {
                    paragraphs_contain_picture_transparency(&footer.paragraphs, transparency)
                }
                Control::Footnote(note) => {
                    paragraphs_contain_picture_transparency(&note.paragraphs, transparency)
                }
                Control::Endnote(note) => {
                    paragraphs_contain_picture_transparency(&note.paragraphs, transparency)
                }
                Control::HiddenComment(comment) => {
                    paragraphs_contain_picture_transparency(&comment.paragraphs, transparency)
                }
                _ => false,
            })
        })
    }

