    fn document_contains_hidden_comment_text(core: &DocumentCore, text: &str) -> bool {
        core.document
            .sections
            .iter()
            .any(|section| paragraphs_contain_hidden_comment_text(&section.paragraphs, text))
    }

    fn paragraphs_contain_hidden_comment_text(
        paragraphs: &[crate::model::paragraph::Paragraph],
        text: &str,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::HiddenComment(comment) => {
                    comment
                        .paragraphs
                        .iter()
                        .any(|para| para.text.contains(text))
                        || paragraphs_contain_hidden_comment_text(&comment.paragraphs, text)
                }
                Control::Table(table) => table
                    .cells
                    .iter()
                    .any(|cell| paragraphs_contain_hidden_comment_text(&cell.paragraphs, text)),
                Control::Header(header) => {
                    paragraphs_contain_hidden_comment_text(&header.paragraphs, text)
                }
                Control::Footer(footer) => {
                    paragraphs_contain_hidden_comment_text(&footer.paragraphs, text)
                }
                Control::Footnote(note) => {
                    paragraphs_contain_hidden_comment_text(&note.paragraphs, text)
                }
                Control::Endnote(note) => {
                    paragraphs_contain_hidden_comment_text(&note.paragraphs, text)
                }
                Control::Shape(shape) => shape
                    .drawing()
                    .map(|drawing| {
                        drawing
                            .text_box
                            .as_ref()
                            .map(|text_box| {
                                paragraphs_contain_hidden_comment_text(&text_box.paragraphs, text)
                            })
                            .unwrap_or(false)
                            || drawing
                                .caption
                                .as_ref()
                                .map(|caption| {
                                    paragraphs_contain_hidden_comment_text(
                                        &caption.paragraphs,
                                        text,
                                    )
                                })
                                .unwrap_or(false)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

