    fn paragraphs_contain_table_shape(
        paragraphs: &[crate::model::paragraph::Paragraph],
        row_count: u16,
        col_count: u16,
        cell_count: usize,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Table(table) => {
                    (table.row_count == row_count
                        && table.col_count == col_count
                        && table.cells.len() == cell_count)
                        || table.cells.iter().any(|cell| {
                            paragraphs_contain_table_shape(
                                &cell.paragraphs,
                                row_count,
                                col_count,
                                cell_count,
                            )
                        })
                }
                Control::Header(header) => paragraphs_contain_table_shape(
                    &header.paragraphs,
                    row_count,
                    col_count,
                    cell_count,
                ),
                Control::Footer(footer) => paragraphs_contain_table_shape(
                    &footer.paragraphs,
                    row_count,
                    col_count,
                    cell_count,
                ),
                Control::Footnote(note) => paragraphs_contain_table_shape(
                    &note.paragraphs,
                    row_count,
                    col_count,
                    cell_count,
                ),
                Control::Endnote(note) => paragraphs_contain_table_shape(
                    &note.paragraphs,
                    row_count,
                    col_count,
                    cell_count,
                ),
                Control::HiddenComment(comment) => paragraphs_contain_table_shape(
                    &comment.paragraphs,
                    row_count,
                    col_count,
                    cell_count,
                ),
                Control::Shape(shape) => shape
                    .drawing()
                    .map(|drawing| {
                        drawing
                            .text_box
                            .as_ref()
                            .map(|text_box| {
                                paragraphs_contain_table_shape(
                                    &text_box.paragraphs,
                                    row_count,
                                    col_count,
                                    cell_count,
                                )
                            })
                            .unwrap_or(false)
                            || drawing
                                .caption
                                .as_ref()
                                .map(|caption| {
                                    paragraphs_contain_table_shape(
                                        &caption.paragraphs,
                                        row_count,
                                        col_count,
                                        cell_count,
                                    )
                                })
                                .unwrap_or(false)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

    fn document_contains_table_cell_format(
        core: &DocumentCore,
        text: &str,
        font_size: i32,
        margin_left: i32,
    ) -> bool {
        core.document.sections.iter().any(|section| {
            paragraphs_contain_table_cell_format(
                &section.paragraphs,
                core,
                text,
                font_size,
                margin_left,
            )
        })
    }

    fn table_cell_format_report(core: &DocumentCore, text: &str) -> String {
        let mut lines = Vec::new();
        for (sec_idx, section) in core.document.sections.iter().enumerate() {
            collect_table_cell_format_report(
                &section.paragraphs,
                core,
                text,
                &format!("sec{sec_idx}"),
                &mut lines,
            );
        }
        if lines.is_empty() {
            format!("no table cell paragraph contains {text:?}")
        } else {
            lines.join("\n")
        }
    }

    fn collect_table_cell_format_report(
        paragraphs: &[crate::model::paragraph::Paragraph],
        core: &DocumentCore,
        text: &str,
        scope: &str,
        lines: &mut Vec<String>,
    ) {
        for (para_idx, para) in paragraphs.iter().enumerate() {
            for (control_idx, control) in para.controls.iter().enumerate() {
                match control {
                    Control::Table(table) => {
                        for (cell_idx, cell) in table.cells.iter().enumerate() {
                            for (cell_para_idx, cell_para) in cell.paragraphs.iter().enumerate() {
                                if cell_para.text.contains(text) {
                                    let char_shape_id = cell_para.char_shape_id_at(0);
                                    let base_size = char_shape_id
                                        .and_then(|id| {
                                            core.document.doc_info.char_shapes.get(id as usize)
                                        })
                                        .map(|shape| shape.base_size);
                                    let para_shape_id = cell_para.para_shape_id;
                                    let margin_left = core
                                        .document
                                        .doc_info
                                        .para_shapes
                                        .get(para_shape_id as usize)
                                        .map(|shape| shape.margin_left);
                                    lines.push(format!(
                                        "{scope}.p{para_idx}.c{control_idx}.cell{cell_idx}.cell_p{cell_para_idx}: text={:?} char_shape={char_shape_id:?} base_size={base_size:?} para_shape={para_shape_id} margin_left={margin_left:?}",
                                        cell_para.text
                                    ));
                                }
                            }
                            collect_table_cell_format_report(
                                &cell.paragraphs,
                                core,
                                text,
                                &format!("{scope}.p{para_idx}.c{control_idx}.cell{cell_idx}"),
                                lines,
                            );
                        }
                    }
                    Control::Header(header) => collect_table_cell_format_report(
                        &header.paragraphs,
                        core,
                        text,
                        &format!("{scope}.p{para_idx}.header{control_idx}"),
                        lines,
                    ),
                    Control::Footer(footer) => collect_table_cell_format_report(
                        &footer.paragraphs,
                        core,
                        text,
                        &format!("{scope}.p{para_idx}.footer{control_idx}"),
                        lines,
                    ),
                    Control::Footnote(note) => collect_table_cell_format_report(
                        &note.paragraphs,
                        core,
                        text,
                        &format!("{scope}.p{para_idx}.footnote{control_idx}"),
                        lines,
                    ),
                    Control::Endnote(note) => collect_table_cell_format_report(
                        &note.paragraphs,
                        core,
                        text,
                        &format!("{scope}.p{para_idx}.endnote{control_idx}"),
                        lines,
                    ),
                    Control::HiddenComment(comment) => collect_table_cell_format_report(
                        &comment.paragraphs,
                        core,
                        text,
                        &format!("{scope}.p{para_idx}.comment{control_idx}"),
                        lines,
                    ),
                    Control::Shape(shape) => {
                        if let Some(drawing) = shape.drawing() {
                            if let Some(text_box) = &drawing.text_box {
                                collect_table_cell_format_report(
                                    &text_box.paragraphs,
                                    core,
                                    text,
                                    &format!("{scope}.p{para_idx}.shape_text{control_idx}"),
                                    lines,
                                );
                            }
                            if let Some(caption) = &drawing.caption {
                                collect_table_cell_format_report(
                                    &caption.paragraphs,
                                    core,
                                    text,
                                    &format!("{scope}.p{para_idx}.shape_caption{control_idx}"),
                                    lines,
                                );
                            }
                        }
                    }
                    _ => {}
                }
            }
        }
    }

    fn document_contains_header_footer_para_format(
        core: &DocumentCore,
        text: &str,
        font_size: i32,
        margin_left: i32,
    ) -> bool {
        core.document.sections.iter().any(|section| {
            section.paragraphs.iter().any(|para| {
                para.controls.iter().any(|control| {
                    let paragraphs = match control {
                        Control::Header(header) => Some(header.paragraphs.as_slice()),
                        Control::Footer(footer) => Some(footer.paragraphs.as_slice()),
                        _ => None,
                    };
                    paragraphs.into_iter().flatten().any(|hf_para| {
                        paragraph_has_format(core, hf_para, text, font_size, margin_left)
                    })
                })
            })
        })
    }

    fn document_contains_shape_text_box_para_format(
        core: &DocumentCore,
        text: &str,
        font_size: i32,
        margin_left: i32,
    ) -> bool {
        core.document.sections.iter().any(|section| {
            section.paragraphs.iter().any(|para| {
                para.controls.iter().any(|control| {
                    let Control::Shape(shape) = control else {
                        return false;
                    };
                    shape
                        .drawing()
                        .and_then(|drawing| drawing.text_box.as_ref())
                        .map(|text_box| {
                            text_box.paragraphs.iter().any(|tb_para| {
                                paragraph_has_format(core, tb_para, text, font_size, margin_left)
                            })
                        })
                        .unwrap_or(false)
                })
            })
        })
    }

    fn shape_text_box_para_format_report(core: &DocumentCore, text: &str) -> String {
        let mut lines = Vec::new();
        for (sec_idx, section) in core.document.sections.iter().enumerate() {
            for (para_idx, para) in section.paragraphs.iter().enumerate() {
                for (control_idx, control) in para.controls.iter().enumerate() {
                    let Control::Shape(shape) = control else {
                        continue;
                    };
                    let Some(text_box) = shape
                        .drawing()
                        .and_then(|drawing| drawing.text_box.as_ref())
                    else {
                        continue;
                    };
                    for (tb_para_idx, tb_para) in text_box.paragraphs.iter().enumerate() {
                        if tb_para.text.contains(text) {
                            let char_shape_id = tb_para.char_shape_id_at(0);
                            let base_size = char_shape_id
                                .and_then(|id| core.document.doc_info.char_shapes.get(id as usize))
                                .map(|shape| shape.base_size);
                            let para_shape_id = tb_para.para_shape_id;
                            let margin_left = core
                                .document
                                .doc_info
                                .para_shapes
                                .get(para_shape_id as usize)
                                .map(|shape| shape.margin_left);
                            lines.push(format!(
                                "sec{sec_idx}.p{para_idx}.shape{control_idx}.text_box_p{tb_para_idx}: text={:?} char_shape={char_shape_id:?} base_size={base_size:?} para_shape={para_shape_id} margin_left={margin_left:?}",
                                tb_para.text
                            ));
                        }
                    }
                }
            }
        }
        if lines.is_empty() {
            format!("no shape text-box paragraph contains {text:?}")
        } else {
            lines.join("\n")
        }
    }

    fn header_footer_para_format_report(core: &DocumentCore, text: &str) -> String {
        let mut lines = Vec::new();
        for (sec_idx, section) in core.document.sections.iter().enumerate() {
            for (para_idx, para) in section.paragraphs.iter().enumerate() {
                for (control_idx, control) in para.controls.iter().enumerate() {
                    let (scope, paragraphs) = match control {
                        Control::Header(header) => ("header", header.paragraphs.as_slice()),
                        Control::Footer(footer) => ("footer", footer.paragraphs.as_slice()),
                        _ => continue,
                    };
                    for (hf_para_idx, hf_para) in paragraphs.iter().enumerate() {
                        if hf_para.text.contains(text) {
                            let char_shape_id = hf_para.char_shape_id_at(0);
                            let base_size = char_shape_id
                                .and_then(|id| core.document.doc_info.char_shapes.get(id as usize))
                                .map(|shape| shape.base_size);
                            let para_shape_id = hf_para.para_shape_id;
                            let margin_left = core
                                .document
                                .doc_info
                                .para_shapes
                                .get(para_shape_id as usize)
                                .map(|shape| shape.margin_left);
                            lines.push(format!(
                                "sec{sec_idx}.p{para_idx}.{scope}{control_idx}.hf_p{hf_para_idx}: text={:?} char_shape={char_shape_id:?} base_size={base_size:?} para_shape={para_shape_id} margin_left={margin_left:?}",
                                hf_para.text
                            ));
                        }
                    }
                }
            }
        }
        if lines.is_empty() {
            format!("no header/footer paragraph contains {text:?}")
        } else {
            lines.join("\n")
        }
    }

    fn paragraph_has_format(
        core: &DocumentCore,
        para: &crate::model::paragraph::Paragraph,
        text: &str,
        font_size: i32,
        margin_left: i32,
    ) -> bool {
        if !para.text.contains(text) {
            return false;
        }
        let char_shape_ok = para
            .char_shape_id_at(0)
            .and_then(|id| core.document.doc_info.char_shapes.get(id as usize))
            .map(|shape| shape.base_size == font_size)
            .unwrap_or(false);
        let para_shape_ok = core
            .document
            .doc_info
            .para_shapes
            .get(para.para_shape_id as usize)
            .map(|shape| shape.margin_left == margin_left)
            .unwrap_or(false);
        char_shape_ok && para_shape_ok
    }

    fn paragraphs_contain_table_cell_format(
        paragraphs: &[crate::model::paragraph::Paragraph],
        core: &DocumentCore,
        text: &str,
        font_size: i32,
        margin_left: i32,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Table(table) => table.cells.iter().any(|cell| {
                    cell.paragraphs.iter().any(|cell_para| {
                        if !cell_para.text.contains(text) {
                            return false;
                        }
                        let char_shape_ok = cell_para
                            .char_shape_id_at(0)
                            .and_then(|id| core.document.doc_info.char_shapes.get(id as usize))
                            .map(|shape| shape.base_size == font_size)
                            .unwrap_or(false);
                        let para_shape_ok = core
                            .document
                            .doc_info
                            .para_shapes
                            .get(cell_para.para_shape_id as usize)
                            .map(|shape| shape.margin_left == margin_left)
                            .unwrap_or(false);
                        char_shape_ok && para_shape_ok
                    }) || paragraphs_contain_table_cell_format(
                        &cell.paragraphs,
                        core,
                        text,
                        font_size,
                        margin_left,
                    )
                }),
                Control::Header(header) => paragraphs_contain_table_cell_format(
                    &header.paragraphs,
                    core,
                    text,
                    font_size,
                    margin_left,
                ),
                Control::Footer(footer) => paragraphs_contain_table_cell_format(
                    &footer.paragraphs,
                    core,
                    text,
                    font_size,
                    margin_left,
                ),
                Control::Footnote(note) => paragraphs_contain_table_cell_format(
                    &note.paragraphs,
                    core,
                    text,
                    font_size,
                    margin_left,
                ),
                Control::Endnote(note) => paragraphs_contain_table_cell_format(
                    &note.paragraphs,
                    core,
                    text,
                    font_size,
                    margin_left,
                ),
                Control::HiddenComment(comment) => paragraphs_contain_table_cell_format(
                    &comment.paragraphs,
                    core,
                    text,
                    font_size,
                    margin_left,
                ),
                Control::Shape(shape) => shape
                    .drawing()
                    .map(|drawing| {
                        drawing
                            .text_box
                            .as_ref()
                            .map(|text_box| {
                                paragraphs_contain_table_cell_format(
                                    &text_box.paragraphs,
                                    core,
                                    text,
                                    font_size,
                                    margin_left,
                                )
                            })
                            .unwrap_or(false)
                            || drawing
                                .caption
                                .as_ref()
                                .map(|caption| {
                                    paragraphs_contain_table_cell_format(
                                        &caption.paragraphs,
                                        core,
                                        text,
                                        font_size,
                                        margin_left,
                                    )
                                })
                                .unwrap_or(false)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

    fn paragraphs_contain_table_cell_text(
        paragraphs: &[crate::model::paragraph::Paragraph],
        text: &str,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Table(table) => table.cells.iter().any(|cell| {
                    cell.paragraphs.iter().any(|para| para.text.contains(text))
                        || paragraphs_contain_table_cell_text(&cell.paragraphs, text)
                }),
                Control::Header(header) => {
                    paragraphs_contain_table_cell_text(&header.paragraphs, text)
                }
                Control::Footer(footer) => {
                    paragraphs_contain_table_cell_text(&footer.paragraphs, text)
                }
                Control::Footnote(note) => {
                    paragraphs_contain_table_cell_text(&note.paragraphs, text)
                }
                Control::Endnote(note) => {
                    paragraphs_contain_table_cell_text(&note.paragraphs, text)
                }
                Control::HiddenComment(comment) => {
                    paragraphs_contain_table_cell_text(&comment.paragraphs, text)
                }
                Control::Shape(shape) => shape
                    .drawing()
                    .map(|drawing| {
                        drawing
                            .text_box
                            .as_ref()
                            .map(|text_box| {
                                paragraphs_contain_table_cell_text(&text_box.paragraphs, text)
                            })
                            .unwrap_or(false)
                            || drawing
                                .caption
                                .as_ref()
                                .map(|caption| {
                                    paragraphs_contain_table_cell_text(&caption.paragraphs, text)
                                })
                                .unwrap_or(false)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

    fn document_contains_bookmark(core: &DocumentCore, name: &str) -> bool {
        core.document
            .sections
            .iter()
            .any(|section| paragraphs_contain_bookmark(&section.paragraphs, name))
    }

    fn paragraphs_contain_bookmark(
        paragraphs: &[crate::model::paragraph::Paragraph],
        name: &str,
    ) -> bool {
        paragraphs.iter().any(|para| {
            para.controls.iter().any(|control| match control {
                Control::Bookmark(bookmark) => bookmark.name == name,
                Control::Table(table) => table
                    .cells
                    .iter()
                    .any(|cell| paragraphs_contain_bookmark(&cell.paragraphs, name)),
                Control::Header(header) => paragraphs_contain_bookmark(&header.paragraphs, name),
                Control::Footer(footer) => paragraphs_contain_bookmark(&footer.paragraphs, name),
                Control::Footnote(note) => paragraphs_contain_bookmark(&note.paragraphs, name),
                Control::Endnote(note) => paragraphs_contain_bookmark(&note.paragraphs, name),
                Control::HiddenComment(comment) => {
                    paragraphs_contain_bookmark(&comment.paragraphs, name)
                }
                Control::Shape(shape) => shape
                    .drawing()
                    .map(|drawing| {
                        drawing
                            .text_box
                            .as_ref()
                            .map(|text_box| paragraphs_contain_bookmark(&text_box.paragraphs, name))
                            .unwrap_or(false)
                            || drawing
                                .caption
                                .as_ref()
                                .map(|caption| {
                                    paragraphs_contain_bookmark(&caption.paragraphs, name)
                                })
                                .unwrap_or(false)
                    })
                    .unwrap_or(false),
                _ => false,
            })
        })
    }

    fn assert_government_page_section_edit(
        core: &DocumentCore,
        expected_margin_header: u32,
        expected_binding: BindingMethod,
        expected_page_num: u16,
        expected_default_tab_spacing: u32,
    ) {
        let section = core
            .document
            .sections
            .first()
            .expect("government document first section");
        let page_def = &section.section_def.page_def;
        assert_eq!(page_def.margin_header, expected_margin_header);
        assert_eq!(page_def.binding, expected_binding);
        assert_eq!(section.section_def.page_num, expected_page_num);
        assert_eq!(
            section.section_def.default_tab_spacing,
            expected_default_tab_spacing
        );
    }

    fn unique_target(name: &str, extension: &str) -> String {
        std::fs::create_dir_all("target/mcp-tests").expect("test output dir");
        let nonce = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .expect("system clock")
            .as_nanos();
        format!("target/mcp-tests/{name}-{nonce}.{extension}")
    }

    fn assert_generated_hwp_record_match_and_blank_drift(
        runtime: &mut ToolRuntime,
        edited_session_id: &str,
        label: &str,
    ) {
        let target = unique_target(label, "hwp");
        let save = call_tool_ok(
            runtime,
            &format!("{label}-save-record"),
            "rhwp_save",
            json!({
                "session_id": edited_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let same = call_tool_ok(
            runtime,
            &format!("{label}-record-same"),
            "rhwp_compare_hwp_records",
            json!({
                "session_id": edited_session_id,
                "other_path": saved_path,
                "max_diffs": 4
            }),
        );
        assert_eq!(same["equal"], true, "{label} saved record diff: {same}");
        assert_eq!(same["difference_count"], 0);

        let blank = call_tool_ok(runtime, &format!("{label}-blank"), "rhwp_new", json!({}));
        let blank_session_id = session_id(&blank);
        let drift = call_tool_ok(
            runtime,
            &format!("{label}-record-drift"),
            "rhwp_compare_hwp_records",
            json!({
                "session_id": edited_session_id,
                "other_session_id": blank_session_id,
                "max_diffs": 8
            }),
        );
        assert_eq!(
            drift["equal"], false,
            "{label} record diff should detect generated edits: {drift}"
        );
        assert!(drift["difference_count"].as_u64().unwrap_or(0) > 0);
        assert!(!drift["differences"].as_array().expect("diffs").is_empty());
    }

    fn inject_hwpx_manifest_entry(
        source: &[u8],
        entry_path: &str,
        entry_bytes: &[u8],
        manifest_id: &str,
        media_type: &str,
    ) -> Vec<u8> {
        use std::io::{Cursor, Read, Write};
        use zip::write::SimpleFileOptions;
        use zip::{CompressionMethod, ZipArchive, ZipWriter};

        let mut archive = ZipArchive::new(Cursor::new(source.to_vec())).expect("source hwpx zip");
        let mut out = Cursor::new(Vec::<u8>::new());
        {
            let mut writer = ZipWriter::new(&mut out);
            let deflated =
                SimpleFileOptions::default().compression_method(CompressionMethod::Deflated);
            let stored = SimpleFileOptions::default().compression_method(CompressionMethod::Stored);
            for idx in 0..archive.len() {
                let mut file = archive.by_index(idx).expect("zip entry");
                let name = file.name().to_string();
                if name == entry_path {
                    continue;
                }
                let mut data = Vec::new();
                file.read_to_end(&mut data).expect("read zip entry");
                if name == "Contents/content.hpf" {
                    let text = String::from_utf8(data).expect("content.hpf utf8");
                    data = inject_content_manifest_item(&text, manifest_id, entry_path, media_type)
                        .into_bytes();
                }
                let options = if name == "mimetype" { stored } else { deflated };
                writer.start_file(name, options).expect("start zip entry");
                writer.write_all(&data).expect("write zip entry");
            }
            writer
                .start_file(entry_path, deflated)
                .expect("start injected entry");
            writer.write_all(entry_bytes).expect("write injected entry");
            writer.finish().expect("finish injected zip");
        }
        out.into_inner()
    }

    fn inject_content_manifest_item(
        content_hpf: &str,
        id: &str,
        href: &str,
        media_type: &str,
    ) -> String {
        if content_hpf.contains(&format!(r#"href="{href}""#)) {
            return content_hpf.to_string();
        }
        let item = format!(r#"<opf:item id="{id}" href="{href}" media-type="{media_type}"/>"#);
        content_hpf.replace("</opf:manifest>", &format!("{item}</opf:manifest>"))
    }

    fn move_content_manifest_item_to_end(content_hpf: &str, href: &str) -> String {
        let href_pos = content_hpf
            .find(&format!(r#"href="{href}""#))
            .expect("manifest href");
        let start = content_hpf[..href_pos]
            .rfind("<opf:item")
            .expect("manifest item start");
        let end = href_pos
            + content_hpf[href_pos..]
                .find("/>")
                .expect("manifest item end")
            + 2;
        let item = &content_hpf[start..end];
        let without = format!("{}{}", &content_hpf[..start], &content_hpf[end..]);
        without.replace("</opf:manifest>", &format!("{item}</opf:manifest>"))
    }

    fn remove_lineseg_arrays(xml: &str) -> String {
        let mut out = String::with_capacity(xml.len());
        let mut rest = xml;
        while let Some(start) = rest.find("<hp:linesegarray") {
            out.push_str(&rest[..start]);
            let after_start = &rest[start..];
            let Some(end_offset) = after_start.find("</hp:linesegarray>") else {
                out.push_str(after_start);
                return out;
            };
            rest = &after_start[end_offset + "</hp:linesegarray>".len()..];
        }
        out.push_str(rest);
        out
    }

    fn replace_hwpx_zip_entry(source: &[u8], entry_path: &str, replacement: &[u8]) -> Vec<u8> {
        use std::io::{Cursor, Read, Write};
        use zip::write::SimpleFileOptions;
        use zip::{CompressionMethod, ZipArchive, ZipWriter};

        let mut archive = ZipArchive::new(Cursor::new(source.to_vec())).expect("source hwpx zip");
        let mut out = Cursor::new(Vec::<u8>::new());
        {
            let mut writer = ZipWriter::new(&mut out);
            let deflated =
                SimpleFileOptions::default().compression_method(CompressionMethod::Deflated);
            let stored = SimpleFileOptions::default().compression_method(CompressionMethod::Stored);
            let mut replaced = false;
            for idx in 0..archive.len() {
                let mut file = archive.by_index(idx).expect("zip entry");
                let name = file.name().to_string();
                let options = if name == "mimetype" { stored } else { deflated };
                writer.start_file(&name, options).expect("start zip entry");
                if name == entry_path {
                    writer.write_all(replacement).expect("write replacement");
                    replaced = true;
                } else {
                    let mut data = Vec::new();
                    file.read_to_end(&mut data).expect("read zip entry");
                    writer.write_all(&data).expect("write zip entry");
                }
            }
            assert!(replaced, "entry not found in source HWPX: {entry_path}");
            writer.finish().expect("finish replaced zip");
        }
        out.into_inner()
    }

    fn zip_entry_bytes(bytes: &[u8], path: &str) -> Option<Vec<u8>> {
        use std::io::{Cursor, Read};
        let mut archive = zip::ZipArchive::new(Cursor::new(bytes.to_vec())).ok()?;
        let mut entry = archive.by_name(path).ok()?;
        let mut out = Vec::new();
        entry.read_to_end(&mut out).ok()?;
        Some(out)
    }

    fn zip_entry_text(bytes: &[u8], path: &str) -> Option<String> {
        zip_entry_bytes(bytes, path).and_then(|bytes| String::from_utf8(bytes).ok())
    }

    #[test]
    fn initialize_returns_server_info() {
        let mut runtime = runtime();
        let response = handle_json_value(
            &mut runtime,
            json!({
                "jsonrpc": "2.0",
                "id": 1,
                "method": "initialize",
                "params": { "protocolVersion": "test-version" }
            }),
        )
        .expect("response");
        assert_eq!(response["result"]["protocolVersion"], "test-version");
        assert_eq!(response["result"]["serverInfo"]["name"], "rhwp-mcp");
    }

    #[test]
    fn tools_list_contains_open() {
        let mut runtime = runtime();
        let response = handle_json_value(
            &mut runtime,
            json!({
                "jsonrpc": "2.0",
                "id": "list",
                "method": "tools/list"
            }),
        )
        .expect("response");
        let tools = response["result"]["tools"].as_array().expect("tools");
        assert!(tools.iter().any(|tool| tool["name"] == "rhwp_open"));
    }

