    #[test]
    fn apply_format_rejects_invalid_props_without_shape_side_effects() {
        let mut runtime = runtime();
        let created = call_tool_ok(&mut runtime, "new-format-validation", "rhwp_new", json!({}));
        let session_id = session_id(&created);
        call_tool_ok(
            &mut runtime,
            "insert-format-validation-text",
            "rhwp_insert_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "text": "format validation"
            }),
        );
        let before_template = call_tool_ok(
            &mut runtime,
            "extract-before-invalid-apply-format",
            "rhwp_extract_document_template",
            json!({ "session_id": session_id }),
        );
        let before_char_shape_count = before_template["stats"]["char_shape_count"]
            .as_u64()
            .expect("before char shape count");
        let before_para_shape_count = before_template["stats"]["para_shape_count"]
            .as_u64()
            .expect("before para shape count");

        let invalid_char = call_tool_error_text(
            &mut runtime,
            "invalid-apply-char-format-props",
            "rhwp_apply_char_format",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "start": 0,
                "end": 6,
                "props": {
                    "fontSize": "large"
                }
            }),
        );
        assert!(
            invalid_char.contains("char_format.fontSize must be an integer"),
            "unexpected invalid char props error: {invalid_char}"
        );

        let invalid_para = call_tool_error_text(
            &mut runtime,
            "invalid-apply-para-format-props",
            "rhwp_apply_para_format",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "props": {
                    "alignment": "middle"
                }
            }),
        );
        assert!(
            invalid_para.contains("para_format.alignment must be one of"),
            "unexpected invalid para props error: {invalid_para}"
        );

        let after_template = call_tool_ok(
            &mut runtime,
            "extract-after-invalid-apply-format",
            "rhwp_extract_document_template",
            json!({ "session_id": session_id }),
        );
        assert_eq!(
            after_template["stats"]["char_shape_count"].as_u64(),
            Some(before_char_shape_count),
            "invalid apply_char_format must not create a CharShape"
        );
        assert_eq!(
            after_template["stats"]["para_shape_count"].as_u64(),
            Some(before_para_shape_count),
            "invalid apply_para_format must not create a ParaShape"
        );
    }

    fn assert_one_of_required(schema: &Value, alternatives: &[&[&str]]) {
        let one_of = schema["oneOf"].as_array().expect("schema oneOf");
        for expected in alternatives {
            assert!(
                one_of.iter().any(|item| {
                    let Some(required) = item["required"].as_array() else {
                        return false;
                    };
                    required.len() == expected.len()
                        && expected.iter().all(|name| required.contains(&json!(name)))
                }),
                "missing oneOf required alternative {expected:?} in {schema}"
            );
        }
    }

    fn assert_any_of_required(schema: &Value, alternatives: &[&[&str]]) {
        let any_of = schema["anyOf"].as_array().expect("schema anyOf");
        for expected in alternatives {
            assert!(
                any_of.iter().any(|item| {
                    let Some(required) = item["required"].as_array() else {
                        return false;
                    };
                    required.len() == expected.len()
                        && expected.iter().all(|name| required.contains(&json!(name)))
                }),
                "missing anyOf required alternative {expected:?} in {schema}"
            );
        }
    }

    #[test]
    fn alternative_argument_groups_reject_ambiguous_inputs() {
        let mut runtime = runtime();
        let blank = call_tool_ok(&mut runtime, "alt-new", "rhwp_new", json!({}));
        let session_id = session_id(&blank);

        let err = call_tool_error_text(
            &mut runtime,
            "alt-ingest",
            "rhwp_new_exam_from_ingest",
            json!({
                "ingest": { "version": "1", "questions": [] },
                "ingest_json": "{\"version\":\"1\",\"questions\":[]}"
            }),
        );
        assert!(err.contains("ingest source accepts exactly one"), "{err}");

        let err = call_tool_error_text(
            &mut runtime,
            "alt-government-report",
            "rhwp_new_government_report",
            json!({
                "report": { "title": "A", "rows": [] },
                "report_json": "{\"title\":\"A\",\"rows\":[]}"
            }),
        );
        assert!(
            err.contains("government report source accepts exactly one"),
            "{err}"
        );

        let err = call_tool_error_text(
            &mut runtime,
            "alt-document-template",
            "rhwp_new_from_document_template",
            json!({
                "template": { "version": "rhwp-document-template-v1" },
                "template_json": "{\"version\":\"rhwp-document-template-v1\"}"
            }),
        );
        assert!(
            err.contains("document template source accepts exactly one"),
            "{err}"
        );

        let err = call_tool_error_text(
            &mut runtime,
            "alt-compare",
            "rhwp_compare_text",
            json!({
                "session_id": session_id,
                "other_session_id": session_id,
                "path": "saved/blank2010.hwp"
            }),
        );
        assert!(err.contains("compare target accepts exactly one"), "{err}");

        let err = call_tool_error_text(
            &mut runtime,
            "alt-compare-profile",
            "rhwp_compare_document_profile",
            json!({
                "session_id": session_id,
                "other_session_id": session_id,
                "path": "saved/blank2010.hwp"
            }),
        );
        assert!(err.contains("compare target accepts exactly one"), "{err}");

        let err = call_tool_error_text(
            &mut runtime,
            "alt-replace",
            "rhwp_replace_text",
            json!({
                "session_id": session_id,
                "query": "a",
                "char_offset": 0,
                "length": 1,
                "new_text": "b"
            }),
        );
        assert!(err.contains("replace target accepts either query"), "{err}");

        let err = call_tool_error_text(
            &mut runtime,
            "alt-field",
            "rhwp_get_field",
            json!({
                "session_id": session_id,
                "field_id": 1,
                "name": "field"
            }),
        );
        assert!(err.contains("field target accepts exactly one"), "{err}");

        let err = call_tool_error_text(
            &mut runtime,
            "alt-picture",
            "rhwp_insert_picture",
            json!({
                "session_id": session_id,
                "para": 0,
                "char_offset": 0,
                "image_base64": minimal_png_base64(),
                "image_path": "missing.png",
                "width": 1000,
                "height": 1000
            }),
        );
        assert!(
            err.contains("picture image source accepts exactly one"),
            "{err}"
        );
    }

