    #[test]
    fn open_then_document_info_roundtrip() {
        let mut runtime = runtime();
        let open = handle_json_value(
            &mut runtime,
            json!({
                "jsonrpc": "2.0",
                "id": "open",
                "method": "tools/call",
                "params": {
                    "name": "rhwp_open",
                    "arguments": { "path": "saved/blank2010.hwp" }
                }
            }),
        )
        .expect("open response");
        assert_eq!(open["result"]["isError"], false);
        let session_id = open["result"]["structuredContent"]["session_id"]
            .as_str()
            .expect("session id")
            .to_string();

        let info = handle_json_value(
            &mut runtime,
            json!({
                "jsonrpc": "2.0",
                "id": "info",
                "method": "tools/call",
                "params": {
                    "name": "rhwp_document_info",
                    "arguments": { "session_id": session_id }
                }
            }),
        )
        .expect("info response");
        assert_eq!(info["result"]["isError"], false);
        assert!(
            info["result"]["structuredContent"]["document_info"]["pageCount"]
                .as_u64()
                .unwrap_or(0)
                >= 1
        );
    }

    #[test]
    fn open_save_roundtrip_reparses_output() {
        let target = unique_target("open-save-roundtrip", "hwp");

        let mut runtime = runtime();
        let open = call_tool_ok(
            &mut runtime,
            "open-save",
            "rhwp_open",
            json!({ "path": "saved/blank2010.hwp" }),
        );
        let original_session_id = session_id(&open);
        let save = call_tool_ok(
            &mut runtime,
            "save-roundtrip",
            "rhwp_save",
            json!({
                "session_id": original_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        assert_eq!(save["ok"], true);
        let path = save["write"]["path"].as_str().expect("saved path");
        let bytes = std::fs::read(path).expect("saved HWP");
        let reparsed = DocumentCore::from_bytes(&bytes).expect("saved HWP reparses");
        assert!(reparsed.page_count() >= 1);
    }

    #[test]
    fn compare_text_detects_edited_field_fixture() {
        let mut runtime = runtime();
        let open = call_tool_ok(
            &mut runtime,
            "open-field-compare",
            "rhwp_open",
            json!({ "path": "samples/field-01.hwp" }),
        );
        let original_session_id = session_id(&open);

        let same = call_tool_ok(
            &mut runtime,
            "compare-same-field",
            "rhwp_compare_text",
            json!({
                "session_id": original_session_id,
                "other_path": "samples/field-01.hwp"
            }),
        );
        assert_eq!(same["equal"], true);
        assert_eq!(same["difference_count"], 0);

        let fields = call_tool_ok(
            &mut runtime,
            "list-compare-fields",
            "rhwp_list_fields",
            json!({ "session_id": original_session_id }),
        );
        let field_id = fields
            .as_array()
            .expect("fields")
            .iter()
            .find(|field| field["fieldType"] == "clickhere")
            .and_then(|field| field["fieldId"].as_u64())
            .expect("clickhere field") as u32;
        call_tool_ok(
            &mut runtime,
            "set-compare-field",
            "rhwp_set_field",
            json!({
                "session_id": original_session_id,
                "field_id": field_id,
                "value": "MCP compare changed"
            }),
        );

        let changed = call_tool_ok(
            &mut runtime,
            "compare-changed-field",
            "rhwp_compare_text",
            json!({
                "session_id": original_session_id,
                "other_path": "samples/field-01.hwp",
                "max_diffs": 8
            }),
        );
        assert_eq!(changed["equal"], false);
        assert!(changed["difference_count"].as_u64().unwrap_or(0) > 0);
        assert!(!changed["differences"].as_array().expect("diffs").is_empty());
    }

    #[test]
    fn text_paragraph_field_markdown_and_close_lifecycle_roundtrip() {
        let target = unique_target("text-paragraph-field-lifecycle", "hwp");
        let mut runtime = runtime();
        let new_doc = call_tool_ok(&mut runtime, "new-text-lifecycle", "rhwp_new", json!({}));
        let doc_session_id = session_id(&new_doc);

        call_tool_ok(
            &mut runtime,
            "insert-lifecycle-text",
            "rhwp_insert_text",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "text": "AlphaBeta"
            }),
        );
        call_tool_ok(
            &mut runtime,
            "delete-lifecycle-text",
            "rhwp_delete_text",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 5,
                "count": 4
            }),
        );
        call_tool_ok(
            &mut runtime,
            "restore-lifecycle-text",
            "rhwp_insert_text",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 5,
                "text": "Beta"
            }),
        );

        let split = call_tool_ok(
            &mut runtime,
            "split-lifecycle-para",
            "rhwp_split_paragraph",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 5
            }),
        );
        assert_eq!(split["paraIdx"], 1);
        let inserted = call_tool_ok(
            &mut runtime,
            "insert-lifecycle-para",
            "rhwp_insert_paragraph",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 2
            }),
        );
        assert_eq!(inserted["paraIdx"], 2);
        call_tool_ok(
            &mut runtime,
            "insert-lifecycle-extra-text",
            "rhwp_insert_text",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 2,
                "char_offset": 0,
                "text": "Gamma"
            }),
        );
        let deleted = call_tool_ok(
            &mut runtime,
            "delete-lifecycle-para",
            "rhwp_delete_paragraph",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 2
            }),
        );
        assert_eq!(deleted["newParagraphCount"], 2);
        let merged = call_tool_ok(
            &mut runtime,
            "merge-lifecycle-para",
            "rhwp_merge_paragraph",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 1
            }),
        );
        assert_eq!(merged["paraIdx"], 0);

        let inserted_field = call_tool_ok(
            &mut runtime,
            "insert-lifecycle-field",
            "rhwp_insert_click_here_field",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 5,
                "guide": "Guide",
                "memo": "Memo",
                "name": "mcp-inline-field",
                "editable": true
            }),
        );
        let field_id = inserted_field["fieldId"].as_u64().expect("field id") as u32;
        assert_eq!(inserted_field["charOffset"], 5);
        let fields = call_tool_ok(
            &mut runtime,
            "list-lifecycle-fields",
            "rhwp_list_fields",
            json!({ "session_id": doc_session_id }),
        );
        assert_eq!(fields.as_array().expect("fields").len(), 1);
        call_tool_ok(
            &mut runtime,
            "set-lifecycle-field",
            "rhwp_set_field",
            json!({
                "session_id": doc_session_id,
                "field_id": field_id,
                "value": "VALUE"
            }),
        );
        let field = call_tool_ok(
            &mut runtime,
            "get-lifecycle-field",
            "rhwp_get_field",
            json!({
                "session_id": doc_session_id,
                "name": "mcp-inline-field"
            }),
        );
        assert_eq!(field["value"], "VALUE");
        call_tool_ok(
            &mut runtime,
            "remove-lifecycle-field",
            "rhwp_remove_field",
            json!({
                "session_id": doc_session_id,
                "section": 0,
                "para": 0,
                "char_offset": 5
            }),
        );
        let fields = call_tool_ok(
            &mut runtime,
            "list-lifecycle-fields-after-remove",
            "rhwp_list_fields",
            json!({ "session_id": doc_session_id }),
        );
        assert!(fields.as_array().expect("fields after remove").is_empty());

        let markdown = call_tool_ok(
            &mut runtime,
            "extract-lifecycle-markdown",
            "rhwp_extract_markdown",
            json!({ "session_id": doc_session_id }),
        );
        assert!(markdown["markdown"]
            .as_str()
            .expect("markdown")
            .contains("AlphaBeta"));

        let core = runtime
            .core_for_test(&doc_session_id)
            .expect("lifecycle core");
        let section = &core.document.sections[0];
        assert_eq!(section.paragraphs.len(), 1);
        assert_eq!(section.paragraphs[0].text, "AlphaBeta");
        assert!(section.paragraphs[0].field_ranges.is_empty());

        let save = call_tool_ok(
            &mut runtime,
            "save-lifecycle",
            "rhwp_save",
            json!({
                "session_id": doc_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let saved = std::fs::read(saved_path).expect("saved lifecycle HWP");
        let reparsed = DocumentCore::from_bytes(&saved).expect("lifecycle HWP reparses");
        assert_eq!(
            reparsed.document.sections[0].paragraphs[0].text,
            "AlphaBeta"
        );
        assert!(reparsed.document.sections[0].paragraphs[0]
            .field_ranges
            .is_empty());

        let closed = call_tool_ok(
            &mut runtime,
            "close-lifecycle",
            "rhwp_close",
            json!({ "session_id": doc_session_id }),
        );
        assert_eq!(closed["ok"], true);
        let err = call_tool_error_text(
            &mut runtime,
            "info-after-close",
            "rhwp_document_info",
            json!({ "session_id": doc_session_id }),
        );
        assert!(err.contains("unknown session"), "{err}");
    }

