    #[test]
    fn document_template_regenerates_equations() {
        fn collect_equation_scripts_from_block(block: &Value, scripts: &mut Vec<String>) {
            match block["type"].as_str() {
                Some("equation") => {
                    if let Some(script) = block["script"].as_str() {
                        scripts.push(script.to_string());
                    }
                }
                Some("table") => {
                    if let Some(rows) = block["cell_blocks"].as_array() {
                        for row in rows {
                            for cell in row.as_array().into_iter().flatten() {
                                for block in cell.as_array().into_iter().flatten() {
                                    collect_equation_scripts_from_block(block, scripts);
                                }
                            }
                        }
                    }
                }
                _ => {}
            }
        }

        fn collect_equation_scripts_from_template(template: &Value) -> Vec<String> {
            let mut scripts = Vec::new();
            for section in template["sections"].as_array().into_iter().flatten() {
                for block in section["blocks"].as_array().into_iter().flatten() {
                    collect_equation_scripts_from_block(block, &mut scripts);
                }
            }
            for hf in template["headers"]
                .as_array()
                .into_iter()
                .flatten()
                .chain(template["footers"].as_array().into_iter().flatten())
            {
                for block in hf["blocks"].as_array().into_iter().flatten() {
                    collect_equation_scripts_from_block(block, &mut scripts);
                }
            }
            scripts
        }

        let mut runtime = runtime();
        let opened = call_tool_ok(
            &mut runtime,
            "open-equation-template",
            "rhwp_open",
            json!({ "path": "samples/eq-01.hwp" }),
        );
        let fixture_session_id = session_id(&opened);

        let extracted = call_tool_ok(
            &mut runtime,
            "extract-equation-template",
            "rhwp_extract_document_template",
            json!({ "session_id": fixture_session_id }),
        );
        let scripts = collect_equation_scripts_from_template(&extracted["template"]);
        assert!(
            !scripts.is_empty(),
            "equation scripts were not captured in template: {extracted}"
        );
        assert_eq!(
            extracted["stats"]["equation_count"].as_u64().unwrap_or(0),
            scripts.len() as u64
        );
        let sample_script = scripts[0].clone();

        let regenerated = call_tool_ok(
            &mut runtime,
            "regenerate-equation-template",
            "rhwp_new_from_document_template",
            json!({ "template": extracted["template"].clone() }),
        );
        let regenerated_session_id = session_id(&regenerated);
        assert_eq!(
            regenerated["template_stats"]["equation_count"]
                .as_u64()
                .unwrap_or(0),
            scripts.len() as u64
        );
        assert!(
            document_contains_equation_script(
                runtime
                    .core_for_test(&regenerated_session_id)
                    .expect("regenerated equation core"),
                &sample_script,
            ),
            "regenerated document does not contain equation script {sample_script:?}"
        );

        let controls = call_tool_ok(
            &mut runtime,
            "list-regenerated-equations",
            "rhwp_list_controls",
            json!({
                "session_id": regenerated_session_id,
                "kind": "Equation",
                "include_nested": true,
                "max_items": 20
            }),
        );
        assert!(
            controls["controls"]
                .as_array()
                .map(|controls| !controls.is_empty())
                .unwrap_or(false),
            "regenerated equation controls were not discoverable: {controls}"
        );

        let reextracted = call_tool_ok(
            &mut runtime,
            "reextract-equation-template",
            "rhwp_extract_document_template",
            json!({ "session_id": regenerated_session_id }),
        );
        let reextracted_scripts = collect_equation_scripts_from_template(&reextracted["template"]);
        assert_eq!(
            reextracted_scripts, scripts,
            "equation scripts changed after template regeneration"
        );

        let export = call_tool_ok(
            &mut runtime,
            "export-regenerated-equation-template",
            "rhwp_export_bytes",
            json!({ "session_id": regenerated_session_id, "format": "hwp" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("regenerated equation HWP reparses");
        assert!(
            document_contains_equation_script(&reparsed, &sample_script),
            "reparsed regenerated equation script not found"
        );
    }

