    #[test]
    fn document_template_regenerates_pictures() {
        fn collect_picture_blocks<'a>(block: &'a Value, pictures: &mut Vec<&'a Value>) {
            match block["type"].as_str() {
                Some("picture") => pictures.push(block),
                Some("table") => {
                    if let Some(rows) = block["cell_blocks"].as_array() {
                        for row in rows {
                            for cell in row.as_array().into_iter().flatten() {
                                for block in cell.as_array().into_iter().flatten() {
                                    collect_picture_blocks(block, pictures);
                                }
                            }
                        }
                    }
                }
                _ => {}
            }
        }

        fn template_picture_blocks(template: &Value) -> Vec<&Value> {
            let mut pictures = Vec::new();
            for section in template["sections"].as_array().into_iter().flatten() {
                for block in section["blocks"].as_array().into_iter().flatten() {
                    collect_picture_blocks(block, &mut pictures);
                }
            }
            for hf in template["headers"]
                .as_array()
                .into_iter()
                .flatten()
                .chain(template["footers"].as_array().into_iter().flatten())
            {
                for block in hf["blocks"].as_array().into_iter().flatten() {
                    collect_picture_blocks(block, &mut pictures);
                }
            }
            pictures
        }

        let mut runtime = runtime();
        let open = call_tool_ok(
            &mut runtime,
            "open-picture-template",
            "rhwp_open",
            json!({ "path": "samples/pic2.hwp" }),
        );
        let original_session_id = session_id(&open);
        let controls = call_tool_ok(
            &mut runtime,
            "list-picture-template-controls",
            "rhwp_list_controls",
            json!({
                "session_id": original_session_id,
                "kind": "Picture",
                "max_items": 10
            }),
        );
        let picture_control = controls["controls"]
            .as_array()
            .expect("picture controls")
            .iter()
            .find(|control| control["scope"] == "body")
            .unwrap_or_else(|| panic!("expected body picture control: {controls}"));
        let mut edit_args = picture_control["edit_target"]
            .as_object()
            .expect("picture edit target")
            .clone();
        let transparency = 42u8;
        edit_args.insert("session_id".to_string(), json!(original_session_id));
        edit_args.insert(
            "props".to_string(),
            json!({
                "transparency": transparency,
                "description": "MCP templated picture"
            }),
        );
        call_tool_ok(
            &mut runtime,
            "set-picture-template-props",
            "rhwp_set_picture_properties",
            Value::Object(edit_args),
        );

        let extracted = call_tool_ok(
            &mut runtime,
            "extract-picture-template",
            "rhwp_extract_document_template",
            json!({ "session_id": original_session_id }),
        );
        let pictures = template_picture_blocks(&extracted["template"]);
        assert!(!pictures.is_empty(), "picture blocks were not extracted");
        assert_eq!(
            extracted["stats"]["picture_count"].as_u64().unwrap_or(0),
            pictures.len() as u64
        );
        assert!(
            pictures.iter().any(|picture| {
                picture["image_base64"].as_str().unwrap_or("").len() > 32
                    && picture["transparency"].as_u64() == Some(transparency as u64)
                    && picture["width"].as_u64().unwrap_or(0) > 0
                    && picture["height"].as_u64().unwrap_or(0) > 0
            }),
            "extracted picture block did not preserve image/properties"
        );

        let regenerated = call_tool_ok(
            &mut runtime,
            "regenerate-picture-template",
            "rhwp_new_from_document_template",
            json!({ "template": extracted["template"].clone() }),
        );
        let regenerated_session_id = session_id(&regenerated);
        assert_eq!(
            regenerated["template_stats"]["picture_count"]
                .as_u64()
                .unwrap_or(0),
            pictures.len() as u64
        );
        assert!(
            document_contains_picture_transparency(
                runtime
                    .core_for_test(&regenerated_session_id)
                    .expect("regenerated picture core"),
                transparency,
            ),
            "regenerated picture transparency not found"
        );

        let controls = call_tool_ok(
            &mut runtime,
            "list-regenerated-picture-template-controls",
            "rhwp_list_controls",
            json!({
                "session_id": regenerated_session_id,
                "kind": "Picture",
                "max_items": 10
            }),
        );
        assert!(
            controls["controls"]
                .as_array()
                .map(|controls| !controls.is_empty())
                .unwrap_or(false),
            "regenerated picture controls were not discoverable: {controls}"
        );

        let reextracted = call_tool_ok(
            &mut runtime,
            "reextract-picture-template",
            "rhwp_extract_document_template",
            json!({ "session_id": regenerated_session_id }),
        );
        let reextracted_pictures = template_picture_blocks(&reextracted["template"]);
        assert_eq!(
            reextracted_pictures.len(),
            pictures.len(),
            "picture count changed after regeneration"
        );
        assert!(
            reextracted_pictures
                .iter()
                .any(|picture| picture["transparency"].as_u64() == Some(transparency as u64)),
            "reextracted picture transparency missing"
        );

        let export = call_tool_ok(
            &mut runtime,
            "export-regenerated-picture-template",
            "rhwp_export_bytes",
            json!({ "session_id": regenerated_session_id, "format": "hwp" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("regenerated picture HWP reparses");
        assert!(
            document_contains_picture_transparency(&reparsed, transparency),
            "reparsed regenerated picture transparency not found"
        );
        assert!(
            !reparsed.document.bin_data_content.is_empty(),
            "reparsed regenerated picture did not keep image BinData"
        );
    }

