    #[test]
    fn extract_document_template_can_preserve_empty_paragraphs() {
        let mut runtime = runtime();
        let created = call_tool_ok(
            &mut runtime,
            "create-empty-paragraph-template-source",
            "rhwp_new_from_document_template",
            json!({
                "template": {
                    "version": "rhwp-document-template-v1",
                    "sections": [{
                        "blocks": [
                            { "type": "paragraph", "text": "alpha" },
                            { "type": "paragraph", "text": "" },
                            { "type": "paragraph", "text": "beta" },
                            { "type": "paragraph", "text": "" }
                        ]
                    }]
                }
            }),
        );
        let session_id = session_id(&created);

        let compact = call_tool_ok(
            &mut runtime,
            "extract-empty-paragraph-template-default",
            "rhwp_extract_document_template",
            json!({ "session_id": session_id }),
        );
        let compact_blocks = compact["template"]["sections"][0]["blocks"]
            .as_array()
            .expect("compact blocks");
        assert_eq!(
            compact["options"]["preserve_empty_paragraphs"], false,
            "default extraction should report compact empty-paragraph mode: {compact}"
        );
        assert_eq!(
            compact_blocks.len(),
            2,
            "default extraction should keep the compact template behavior: {compact}"
        );

        let preserved = call_tool_ok(
            &mut runtime,
            "extract-empty-paragraph-template-preserved",
            "rhwp_extract_document_template",
            json!({
                "session_id": session_id,
                "preserve_empty_paragraphs": true
            }),
        );
        let preserved_blocks = preserved["template"]["sections"][0]["blocks"]
            .as_array()
            .expect("preserved blocks");
        let empty_count = preserved_blocks
            .iter()
            .filter(|block| block["type"] == "paragraph" && block["text"] == "")
            .count();
        assert_eq!(
            preserved["options"]["preserve_empty_paragraphs"], true,
            "preserve mode should be reported: {preserved}"
        );
        assert_eq!(
            preserved_blocks.len(),
            4,
            "preserve mode should retain blank paragraph blocks: {preserved}"
        );
        assert_eq!(empty_count, 2, "empty paragraph count drifted: {preserved}");
    }

    #[test]
    fn document_template_reuses_host_group_for_table_and_picture_controls() {
        let mut runtime = runtime();
        let created = call_tool_ok(
            &mut runtime,
            "create-shared-host-control-template",
            "rhwp_new_from_document_template",
            json!({
                "template": {
                    "version": "rhwp-document-template-v1",
                    "sections": [{
                        "blocks": [
                            {
                                "type": "table",
                                "host_group": 7,
                                "rows": [["chart data"]],
                                "line_segments": [{
                                    "text_start": 0,
                                    "vertical_pos": 18146,
                                    "line_height": 1100,
                                    "text_height": 1100,
                                    "baseline_distance": 935,
                                    "line_spacing": 660,
                                    "column_start": 0,
                                    "segment_width": 47833,
                                    "tag": 393216
                                }]
                            },
                            {
                                "type": "picture",
                                "host_group": 7,
                                "image_base64": minimal_png_base64(),
                                "extension": "png",
                                "width": 3600,
                                "height": 2400,
                                "natural_width_px": 1,
                                "natural_height_px": 1,
                                "treat_as_char": true,
                                "description": "chart picture"
                            }
                        ]
                    }]
                }
            }),
        );
        let session_id = session_id(&created);
        let core = runtime
            .core_for_test(&session_id)
            .expect("shared-host template core");
        let paragraph = &core.document.sections[0].paragraphs[0];
        let draw_controls = paragraph
            .controls
            .iter()
            .filter(|control| matches!(control, Control::Table(_) | Control::Picture(_)))
            .collect::<Vec<_>>();
        assert_eq!(
            draw_controls.len(),
            2,
            "table and picture controls should share one host paragraph"
        );
        assert!(
            matches!(draw_controls[0], Control::Table(_)),
            "first host control should be the table"
        );
        assert!(
            matches!(draw_controls[1], Control::Picture(_)),
            "second host control should be the picture"
        );
        assert_eq!(paragraph.line_segs[0].vertical_pos, 18146);

        let reextracted = call_tool_ok(
            &mut runtime,
            "reextract-shared-host-control-template",
            "rhwp_extract_document_template",
            json!({ "session_id": session_id }),
        );
        let blocks = reextracted["template"]["sections"][0]["blocks"]
            .as_array()
            .expect("shared host blocks");
        assert_eq!(blocks.len(), 2, "{reextracted}");
        assert_eq!(blocks[0]["type"], "table");
        assert_eq!(blocks[1]["type"], "picture");
        let table_host_group = blocks[0]["host_group"]
            .as_u64()
            .expect("table block should retain an automatic host_group");
        let picture_host_group = blocks[1]["host_group"]
            .as_u64()
            .expect("picture block should retain an automatic host_group");
        assert_eq!(
            table_host_group, picture_host_group,
            "table and picture blocks from the same source paragraph should share host_group"
        );
    }

    #[test]
    fn government_template_compact_artifacts_respects_source_page_count() {
        let mut runtime = runtime();
        let opened = call_tool_ok(
            &mut runtime,
            "open-government-template-compact-source",
            "rhwp_open",
            json!({ "path": "samples/2025년 기부·답례품 실적 지자체 보고서_양식.hwpx" }),
        );
        assert_eq!(opened["document_info"]["pageCount"], 30, "{opened}");
        let source_session = session_id(&opened);
        let extracted = call_tool_ok(
            &mut runtime,
            "extract-government-template-compact-source",
            "rhwp_extract_document_template",
            json!({ "session_id": source_session }),
        );
        assert_eq!(
            extracted["template"]["source_page_count"], 30,
            "source page count should be captured in document-template: {extracted}"
        );
        let government_blocks = extracted["template"]["sections"][0]["blocks"]
            .as_array()
            .expect("government template blocks");
        let cancel_picture = government_blocks
            .iter()
            .find(|block| {
                block["type"] == "picture"
                    && block["description"]
                        .as_str()
                        .is_some_and(|description| description.contains("월별_기부취소"))
            })
            .expect("monthly cancellation picture block");
        assert_eq!(
            cancel_picture["object_layout"]["rhwp_page_top_offset_hint"], true,
            "page-break TAC picture offset hint missing: {cancel_picture}"
        );
        let horizontal_offset = cancel_picture["object_layout"]["horizontal_offset"]
            .as_u64()
            .unwrap_or_default();
        let vertical_offset = cancel_picture["object_layout"]["vertical_offset"]
            .as_u64()
            .unwrap_or_default();
        assert!(
            (2_600..=2_700).contains(&horizontal_offset)
                && (6_600..=6_700).contains(&vertical_offset),
            "page-break TAC picture offset hint drifted: {cancel_picture}"
        );

        let regenerated = call_tool_ok(
            &mut runtime,
            "regenerate-government-template-compact-limited",
            "rhwp_new_from_document_template",
            json!({
                "template": extracted["template"].clone(),
                "page_flow_policy": "compact_artifacts"
            }),
        );
        assert_eq!(
            regenerated["document_info"]["pageCount"], 30,
            "limited compact should preserve authored government fixture page count: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["source_page_count"], 30,
            "source page count missing from compact report: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["precompact_page_count"], 33,
            "precompact page count should expose over-split baseline: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["compact_report"]
                ["empty_paragraph_page_breaks_removed"],
            2,
            "empty artifact count drifted: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["compact_report"]
                ["sibling_paragraph_page_breaks_removed"],
            1,
            "sibling artifact count drifted: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["compact_report"]["floating_object_page_breaks_removed"],
            0,
            "limited compact should not over-remove floating page breaks for this fixture: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["compact_report"]["inline_picture_page_breaks_removed"],
            0,
            "limited compact should not over-remove inline picture page breaks for this fixture: {regenerated}"
        );
        assert_eq!(
            regenerated["page_flow_policy"]["compact_report"]["total_removed"], 3,
            "limited compact total removal count drifted: {regenerated}"
        );

        let regenerated_session = session_id(&regenerated);
        let matched = call_tool_ok(
            &mut runtime,
            "match-government-template-compact-limited",
            "rhwp_match_render_pages",
            json!({
                "session_id": source_session,
                "other_session_id": regenerated_session,
                "source_page": 17,
                "start_page": 16,
                "end_page": 20,
                "max_matches": 1
            }),
        );
        assert_eq!(
            matched["matches"][0]["page"], 17,
            "regenerated page 18 should remain aligned after limited compact: {matched}"
        );
        assert!(
            matched["matches"][0]["score"].as_f64().unwrap_or_default() > 0.95,
            "government page match score regressed: {matched}"
        );

        fn find_svg_text_sequence_y(svg: &str, sequence: &[&str]) -> Option<f64> {
            let mut runs = Vec::new();
            for chunk in svg.split("<text").skip(1) {
                let close = chunk.find('>')?;
                let attrs = &chunk[..close];
                let text_end = chunk[close + 1..].find("</text>")? + close + 1;
                let text = &chunk[close + 1..text_end];
                let y = attrs
                    .split("y=\"")
                    .nth(1)
                    .and_then(|rest| rest.split('"').next())
                    .and_then(|value| value.parse::<f64>().ok())?;
                runs.push((text.to_string(), y));
            }
            runs.windows(sequence.len()).find_map(|window| {
                window
                    .iter()
                    .zip(sequence.iter())
                    .all(|((text, _), expected)| text == expected)
                    .then_some(window[0].1)
            })
        }

        let source_svg = call_tool_ok(
            &mut runtime,
            "render-government-template-source-page18",
            "rhwp_render_svg",
            json!({ "session_id": source_session, "page": 17 }),
        );
        let regenerated_svg = call_tool_ok(
            &mut runtime,
            "render-government-template-regenerated-page18",
            "rhwp_render_svg",
            json!({ "session_id": regenerated_session, "page": 17 }),
        );
        let title_sequence = ["2", ".", "답", "례", "품", "통", "계"];
        let source_title_y = find_svg_text_sequence_y(
            source_svg["svg"].as_str().unwrap_or_default(),
            &title_sequence,
        )
        .expect("source page 18 title y");
        let regenerated_title_y = find_svg_text_sequence_y(
            regenerated_svg["svg"].as_str().unwrap_or_default(),
            &title_sequence,
        )
        .expect("regenerated page 18 title y");
        assert!(
            (source_title_y - regenerated_title_y).abs() <= 32.0,
            "government page 18 title vertical gap regressed: source={source_title_y}, regenerated={regenerated_title_y}"
        );
        let subtitle_sequence = [
            "(", "1", ")", "카", "테", "고", "리", "별", "답", "례", "품", "등", "록", "건", "수",
        ];
        let source_subtitle_y = find_svg_text_sequence_y(
            source_svg["svg"].as_str().unwrap_or_default(),
            &subtitle_sequence,
        )
        .expect("source page 18 subtitle y");
        let regenerated_subtitle_y = find_svg_text_sequence_y(
            regenerated_svg["svg"].as_str().unwrap_or_default(),
            &subtitle_sequence,
        )
        .expect("regenerated page 18 subtitle y");
        assert!(
            (source_subtitle_y - regenerated_subtitle_y).abs() <= 32.0,
            "government page 18 subtitle vertical gap regressed: source={source_subtitle_y}, regenerated={regenerated_subtitle_y}"
        );
    }

