    #[test]
    fn chart_hwpx_save_preserves_ole_controls() {
        let fixtures = [
            ("chart-pie", "samples/chart/원형/2차원원형.hwpx"),
            ("chart-line", "samples/chart/라인/꺽은선형.hwpx"),
            (
                "chart-column",
                "samples/chart/세로막대형/묶은세로막대형.hwpx",
            ),
        ];
        let mut runtime = runtime();
        for (idx, (name, path)) in fixtures.iter().enumerate() {
            let original_bytes = std::fs::read(path).expect("chart fixture");
            let original_core = DocumentCore::from_bytes(&original_bytes)
                .unwrap_or_else(|err| panic!("{path}: {err}"));
            let original_ole_count = count_ole_controls(&original_core);
            assert!(
                original_ole_count > 0,
                "{path} should expose at least one Ole control"
            );

            let target = unique_target(&format!("{name}-ole-preserve"), "hwpx");
            let open = call_tool_ok(
                &mut runtime,
                &format!("open-chart-ole-{idx}"),
                "rhwp_open",
                json!({ "path": path }),
            );
            let session_id = session_id(&open);
            let controls = call_tool_ok(
                &mut runtime,
                &format!("list-chart-ole-{idx}"),
                "rhwp_list_controls",
                json!({
                    "session_id": session_id,
                    "kind": "Ole",
                    "include_nested": true
                }),
            );
            assert_eq!(
                controls["control_count"].as_u64().unwrap_or(0) as usize,
                original_ole_count,
                "{path} MCP list_controls should discover all Ole controls"
            );

            let save = call_tool_ok(
                &mut runtime,
                &format!("save-chart-ole-{idx}"),
                "rhwp_save",
                json!({
                    "session_id": session_id,
                    "path": target,
                    "format": "hwpx",
                    "overwrite": true
                }),
            );
            let saved_path = save["write"]["path"].as_str().expect("saved path");
            let saved_bytes = std::fs::read(saved_path).expect("saved chart HWPX");
            let saved_core = DocumentCore::from_bytes(&saved_bytes)
                .unwrap_or_else(|err| panic!("{path}: {err}"));
            assert_eq!(
                count_ole_controls(&saved_core),
                original_ole_count,
                "{path} saved HWPX should preserve Ole control count"
            );
        }
    }

    #[test]
    fn chart_ole_shape_properties_edit_save_reopen_roundtrip() {
        let mut runtime = runtime();
        let path = "samples/chart/세로막대형/묶은세로막대형.hwpx";
        let target = unique_target("chart-ole-shape-props", "hwpx");
        let open = call_tool_ok(
            &mut runtime,
            "open-chart-ole-shape-props",
            "rhwp_open",
            json!({ "path": path }),
        );
        let chart_session_id = session_id(&open);
        let controls = call_tool_ok(
            &mut runtime,
            "list-chart-ole-shape-props",
            "rhwp_list_controls",
            json!({
                "session_id": chart_session_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let first = controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing OLE control: {controls}"));
        let target_info = &first["edit_target"];
        let section = target_info["section"].as_u64().unwrap() as usize;
        let para = target_info["para"].as_u64().unwrap() as usize;
        let control = target_info["control"].as_u64().unwrap() as usize;
        let before = call_tool_ok(
            &mut runtime,
            "get-chart-ole-shape-props-before",
            "rhwp_get_shape_properties",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        let before_width = before["width"].as_u64().expect("shape width") as u32;
        let edited_width = before_width + 720;
        let changed = call_tool_ok(
            &mut runtime,
            "set-chart-ole-shape-props",
            "rhwp_set_shape_properties",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control,
                "props": { "width": edited_width }
            }),
        );
        assert_eq!(changed["ok"], true, "shape property edit failed: {changed}");
        let edited = call_tool_ok(
            &mut runtime,
            "get-chart-ole-shape-props-after",
            "rhwp_get_shape_properties",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(edited["width"].as_u64().unwrap() as u32, edited_width);

        let save = call_tool_ok(
            &mut runtime,
            "save-chart-ole-shape-props",
            "rhwp_save",
            json!({
                "session_id": chart_session_id,
                "path": target,
                "format": "hwpx",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let reopened = call_tool_ok(
            &mut runtime,
            "reopen-chart-ole-shape-props",
            "rhwp_open",
            json!({ "path": saved_path }),
        );
        let reopened_id = session_id(&reopened);
        let reopened_controls = call_tool_ok(
            &mut runtime,
            "list-reopened-chart-ole-shape-props",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let reopened_first = reopened_controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing reopened OLE control: {reopened_controls}"));
        let reopened_target = &reopened_first["edit_target"];
        let reopened_props = call_tool_ok(
            &mut runtime,
            "get-reopened-chart-ole-shape-props",
            "rhwp_get_shape_properties",
            json!({
                "session_id": reopened_id,
                "section": reopened_target["section"].as_u64().unwrap() as usize,
                "para": reopened_target["para"].as_u64().unwrap() as usize,
                "control": reopened_target["control"].as_u64().unwrap() as usize
            }),
        );
        assert_eq!(
            reopened_props["width"].as_u64().unwrap() as u32,
            edited_width,
            "edited OLE width did not survive save/reopen: {reopened_props}"
        );
    }

    #[test]
    fn legacy_ole_contents_chart_data_readonly_surface_roundtrip() {
        let mut runtime = runtime();
        let fixtures = [
            (
                "legacy-ole-contents-hwp",
                "samples/143E433F503322BD33.hwp",
                "hwp",
                2,
            ),
            (
                "legacy-ole-contents-hwpx",
                "samples/hwpx/143E433F503322BD33.hwpx",
                "hwpx",
                3,
            ),
        ];

        for (label, path, format, expected_bin_data_id) in fixtures {
            let target = unique_target(label, format);
            let open = call_tool_ok(
                &mut runtime,
                &format!("open-{label}"),
                "rhwp_open",
                json!({ "path": path }),
            );
            let chart_session_id = session_id(&open);
            let controls = call_tool_ok(
                &mut runtime,
                &format!("list-{label}"),
                "rhwp_list_controls",
                json!({
                    "session_id": chart_session_id,
                    "kind": "Ole",
                    "include_nested": true
                }),
            );
            let first = controls["controls"]
                .as_array()
                .and_then(|items| items.first())
                .unwrap_or_else(|| panic!("missing legacy OLE control in {path}: {controls}"));
            let target_info = &first["edit_target"];
            let args = json!({
                "session_id": chart_session_id,
                "section": target_info["section"].as_u64().unwrap() as usize,
                "para": target_info["para"].as_u64().unwrap() as usize,
                "control": target_info["control"].as_u64().unwrap() as usize
            });

            let before = call_tool_ok(
                &mut runtime,
                &format!("get-{label}"),
                "rhwp_get_chart_data",
                args.clone(),
            );
            assert_eq!(before["sourceKind"], "LegacyOleChartContents", "{before}");
            assert_eq!(before["binDataId"], expected_bin_data_id, "{before}");
            assert_eq!(before["editable"], false, "{before}");
            assert_eq!(before["rawEditable"], false, "{before}");
            assert_eq!(before["semanticSupported"], true, "{before}");
            assert_eq!(before["semanticSource"], "legacy_ole_contents", "{before}");
            assert_eq!(before["chartType"], "Unknown", "{before}");
            assert_eq!(before["title"], "연금 재정 전망", "{before}");
            assert_eq!(before["categoryCount"], 4, "{before}");
            assert_eq!(before["seriesCount"], 3, "{before}");
            assert_eq!(before["categories"][0], "2010년", "{before}");
            assert_eq!(before["series"][0]["name"], "적립금", "{before}");
            assert_eq!(before["series"][0]["values"][0], 328.0, "{before}");
            assert_eq!(before["rawOleContentsLength"], 9876, "{before}");
            assert_eq!(before["oleChartIrSchema"], "rhwp.oleChartIr", "{before}");
            assert_eq!(before["oleChartIrVersion"], 1, "{before}");
            assert!(
                before["oleChartIrBase64"]
                    .as_str()
                    .is_some_and(|value| !value.is_empty()),
                "{before}"
            );

            let edit_error = call_tool_error_text(
                &mut runtime,
                &format!("set-readonly-{label}"),
                "rhwp_set_chart_data",
                json!({
                    "session_id": chart_session_id,
                    "section": target_info["section"].as_u64().unwrap() as usize,
                    "para": target_info["para"].as_u64().unwrap() as usize,
                    "control": target_info["control"].as_u64().unwrap() as usize,
                    "props": { "title": "MCP should not edit legacy Contents yet" }
                }),
            );
            assert!(
                edit_error.contains("legacy OLE Contents chart"),
                "unexpected readonly error: {edit_error}"
            );

            let save = call_tool_ok(
                &mut runtime,
                &format!("save-{label}"),
                "rhwp_save",
                json!({
                    "session_id": chart_session_id,
                    "path": target,
                    "format": format,
                    "overwrite": true
                }),
            );
            let saved_path = save["write"]["path"].as_str().expect("saved path");
            let reopened = call_tool_ok(
                &mut runtime,
                &format!("reopen-{label}"),
                "rhwp_open",
                json!({ "path": saved_path }),
            );
            let reopened_id = session_id(&reopened);
            let reopened_controls = call_tool_ok(
                &mut runtime,
                &format!("list-reopened-{label}"),
                "rhwp_list_controls",
                json!({
                    "session_id": reopened_id,
                    "kind": "Ole",
                    "include_nested": true
                }),
            );
            let reopened_first = reopened_controls["controls"]
                .as_array()
                .and_then(|items| items.first())
                .unwrap_or_else(|| {
                    panic!("missing reopened legacy OLE in {path}: {reopened_controls}")
                });
            let reopened_target = &reopened_first["edit_target"];
            let reopened_data = call_tool_ok(
                &mut runtime,
                &format!("get-reopened-{label}"),
                "rhwp_get_chart_data",
                json!({
                    "session_id": reopened_id,
                    "section": reopened_target["section"].as_u64().unwrap() as usize,
                    "para": reopened_target["para"].as_u64().unwrap() as usize,
                    "control": reopened_target["control"].as_u64().unwrap() as usize
                }),
            );
            assert_eq!(
                reopened_data["rawOleContentsHash"], before["rawOleContentsHash"],
                "{reopened_data}"
            );
            assert_eq!(reopened_data["title"], "연금 재정 전망", "{reopened_data}");
            assert_eq!(reopened_data["categoryCount"], 4, "{reopened_data}");
            assert_eq!(reopened_data["seriesCount"], 3, "{reopened_data}");
        }
    }

    #[test]
    fn native_hwp_chart_data_raw_payload_get_set_save_reopen_roundtrip() {
        let mut runtime = runtime();
        let target = unique_target("native-hwp-chart-data-raw", "hwp");
        let initial_raw = vec![0x10, 0x20, 0x30, 0x40, 0x50, 0x60];
        let replacement_raw = vec![0x61, 0x52, 0x43, 0x34, 0x25, 0x16, 0x07];
        let initial_raw_base64 = BASE64.encode(&initial_raw);
        let replacement_raw_base64 = BASE64.encode(&replacement_raw);

        let created = call_tool_ok(
            &mut runtime,
            "create-native-chart-data-raw-template",
            "rhwp_new_from_document_template",
            json!({
                "template": {
                    "version": "rhwp-document-template-v1",
                    "sections": [{
                        "blocks": [
                            { "type": "paragraph", "text": "native chart raw smoke" },
                            {
                                "type": "object_placeholder",
                                "object_kind": "chart",
                                "shape_kind": "Chart",
                                "description": "native CHART_DATA raw smoke",
                                "placeholder_text": "[native chart]",
                                "width": 7200,
                                "height": 4200,
                                "treat_as_char": true,
                                "raw_hwp_chart_data_base64": initial_raw_base64.clone()
                            }
                        ]
                    }]
                }
            }),
        );
        let chart_session_id = session_id(&created);

        let controls = call_tool_ok(
            &mut runtime,
            "list-native-chart-data-raw",
            "rhwp_list_controls",
            json!({
                "session_id": chart_session_id,
                "kind": "Chart",
                "include_nested": true
            }),
        );
        let first = controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing native Chart control: {controls}"));
        let target_info = &first["edit_target"];
        let section = target_info["section"].as_u64().unwrap() as usize;
        let para = target_info["para"].as_u64().unwrap() as usize;
        let control = target_info["control"].as_u64().unwrap() as usize;

        let before = call_tool_ok(
            &mut runtime,
            "get-native-chart-data-raw-before",
            "rhwp_get_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(before["sourceKind"], "HwpChartData", "{before}");
        assert_eq!(before["semanticSupported"], false, "{before}");
        assert_eq!(before["rawEditable"], true, "{before}");
        assert_eq!(
            before["rawHwpChartDataLength"].as_u64().unwrap() as usize,
            initial_raw.len(),
            "{before}"
        );
        assert_eq!(before["rawHwpChartDataBase64"], initial_raw_base64);

        let edited = call_tool_ok(
            &mut runtime,
            "set-native-chart-data-raw",
            "rhwp_set_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control,
                "props": {
                    "rawHwpChartDataBase64": replacement_raw_base64.clone()
                }
            }),
        );
        assert_eq!(edited["sourceKind"], "HwpChartData", "{edited}");
        assert_eq!(edited["rawReplaced"], true, "{edited}");
        assert_eq!(
            edited["rawHwpChartDataLength"].as_u64().unwrap() as usize,
            replacement_raw.len(),
            "{edited}"
        );
        assert_eq!(edited["rawHwpChartDataBase64"], replacement_raw_base64);

        let save = call_tool_ok(
            &mut runtime,
            "save-native-chart-data-raw",
            "rhwp_save",
            json!({
                "session_id": chart_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let reopened = call_tool_ok(
            &mut runtime,
            "reopen-native-chart-data-raw",
            "rhwp_open",
            json!({ "path": saved_path }),
        );
        let reopened_id = session_id(&reopened);
        let reopened_controls = call_tool_ok(
            &mut runtime,
            "list-reopened-native-chart-data-raw",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_id,
                "kind": "Chart",
                "include_nested": true
            }),
        );
        let reopened_first = reopened_controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| {
                panic!("missing reopened native Chart control: {reopened_controls}")
            });
        let reopened_target = &reopened_first["edit_target"];
        let reopened_data = call_tool_ok(
            &mut runtime,
            "get-reopened-native-chart-data-raw",
            "rhwp_get_chart_data",
            json!({
                "session_id": reopened_id,
                "section": reopened_target["section"].as_u64().unwrap() as usize,
                "para": reopened_target["para"].as_u64().unwrap() as usize,
                "control": reopened_target["control"].as_u64().unwrap() as usize
            }),
        );
        assert_eq!(reopened_data["sourceKind"], "HwpChartData");
        assert_eq!(reopened_data["semanticSupported"], false);
        assert_eq!(
            reopened_data["rawHwpChartDataBase64"],
            replacement_raw_base64
        );
    }

