    #[test]
    fn native_hwp_chart_data_opaque_semantic_update_rejected_no_side_effect() {
        let mut runtime = runtime();
        let opaque_raw = vec![0x91, 0x92, 0x93, 0x94, 0xa5, 0xb6];
        let opaque_raw_base64 = BASE64.encode(&opaque_raw);

        let created = call_tool_ok(
            &mut runtime,
            "create-native-chart-data-opaque-template",
            "rhwp_new_from_document_template",
            json!({
                "template": {
                    "version": "rhwp-document-template-v1",
                    "sections": [{
                        "blocks": [
                            { "type": "paragraph", "text": "native chart opaque semantic guard" },
                            {
                                "type": "object_placeholder",
                                "object_kind": "chart",
                                "shape_kind": "Chart",
                                "description": "native CHART_DATA opaque semantic guard",
                                "placeholder_text": "[native opaque chart]",
                                "width": 7200,
                                "height": 4200,
                                "treat_as_char": true,
                                "raw_hwp_chart_data_base64": opaque_raw_base64
                            }
                        ]
                    }]
                }
            }),
        );
        let session = session_id(&created);
        let controls = call_tool_ok(
            &mut runtime,
            "list-native-chart-data-opaque",
            "rhwp_list_controls",
            json!({
                "session_id": session,
                "kind": "Chart",
                "include_nested": true
            }),
        );
        let first = controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing native opaque Chart control: {controls}"));
        let target_info = &first["edit_target"];
        let section = target_info["section"].as_u64().unwrap() as usize;
        let para = target_info["para"].as_u64().unwrap() as usize;
        let control = target_info["control"].as_u64().unwrap() as usize;

        let before = call_tool_ok(
            &mut runtime,
            "get-native-chart-data-opaque-before",
            "rhwp_get_chart_data",
            json!({
                "session_id": session,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(before["sourceKind"], "HwpChartData", "{before}");
        assert_eq!(before["semanticSupported"], false, "{before}");
        assert_eq!(before["rawHwpChartDataBase64"], opaque_raw_base64);

        let error = call_tool_error_text(
            &mut runtime,
            "set-native-chart-data-opaque-semantic-rejected",
            "rhwp_set_chart_data",
            json!({
                "session_id": session,
                "section": section,
                "para": para,
                "control": control,
                "props": {
                    "title": "Should not rewrite opaque payload"
                }
            }),
        );
        assert!(
            error.contains("rhwp-generated semantic payloads"),
            "unexpected opaque native chart semantic error: {error}"
        );

        let after = call_tool_ok(
            &mut runtime,
            "get-native-chart-data-opaque-after",
            "rhwp_get_chart_data",
            json!({
                "session_id": session,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(after["semanticSupported"], false, "{after}");
        assert_eq!(
            after["rawHwpChartDataBase64"], before["rawHwpChartDataBase64"],
            "opaque native chart semantic rejection changed raw payload"
        );
    }

