    #[test]
    fn chart_ole_view_3d_edit_save_reopen_roundtrip() {
        let mut runtime = runtime();
        let path = "samples/chart/세로막대형/3차원묶은세로막대형.hwpx";
        let target = unique_target("chart-ole-view-3d", "hwpx");
        let open = call_tool_ok(
            &mut runtime,
            "open-chart-ole-view-3d",
            "rhwp_open",
            json!({ "path": path }),
        );
        let chart_session_id = session_id(&open);
        let controls = call_tool_ok(
            &mut runtime,
            "list-chart-ole-view-3d",
            "rhwp_list_controls",
            json!({
                "session_id": chart_session_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let first = controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing 3D OLE control: {controls}"));
        let target_info = &first["edit_target"];
        let section = target_info["section"].as_u64().unwrap() as usize;
        let para = target_info["para"].as_u64().unwrap() as usize;
        let control = target_info["control"].as_u64().unwrap() as usize;

        let before = call_tool_ok(
            &mut runtime,
            "get-chart-view-3d-before",
            "rhwp_get_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(before["sourceKind"], "OoxmlChart", "{before}");
        assert_eq!(before["chartType"], "Column", "{before}");
        assert_eq!(before["view3DRotationX"], 15, "{before}");
        assert_eq!(before["view3DRotationY"], 20, "{before}");
        assert_eq!(before["view3DPerspective"], 30, "{before}");
        assert_eq!(before["view3DRightAngleAxes"], true, "{before}");
        assert_eq!(before["view3DHeightPercent"], 100, "{before}");
        assert_eq!(before["view3DDepthPercent"], 100, "{before}");
        assert_eq!(before["bar3DGapDepth"], 150, "{before}");
        assert_eq!(before["bar3DShape"], "box", "{before}");

        let edited = call_tool_ok(
            &mut runtime,
            "set-chart-view-3d",
            "rhwp_set_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control,
                "props": {
                    "view3DRotationX": 25,
                    "view3DRotationY": 35,
                    "view3DPerspective": 45,
                    "view3DRightAngleAxes": false,
                    "view3DHeightPercent": 120,
                    "view3DDepthPercent": 140,
                    "bar3DGapDepth": 210,
                    "bar3DShape": "cylinder"
                }
            }),
        );
        assert_eq!(edited["view3DRotationX"], 25, "{edited}");
        assert_eq!(edited["view3DRotationY"], 35, "{edited}");
        assert_eq!(edited["view3DPerspective"], 45, "{edited}");
        assert_eq!(edited["view3DRightAngleAxes"], false, "{edited}");
        assert_eq!(edited["view3DHeightPercent"], 120, "{edited}");
        assert_eq!(edited["view3DDepthPercent"], 140, "{edited}");
        assert_eq!(edited["bar3DGapDepth"], 210, "{edited}");
        assert_eq!(edited["bar3DShape"], "cylinder", "{edited}");

        let save = call_tool_ok(
            &mut runtime,
            "save-chart-view-3d",
            "rhwp_save",
            json!({
                "session_id": chart_session_id,
                "path": target,
                "format": "hwpx",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let saved_bytes = std::fs::read(saved_path).expect("saved 3D chart HWPX");
        let chart_xml =
            zip_entry_text(&saved_bytes, "Chart/chart1.xml").expect("saved Chart/chart1.xml");
        assert!(chart_xml.contains(r#"<c:rAngAx val="0"/>"#), "{chart_xml}");
        assert!(chart_xml.contains(r#"<c:rotX val="25"/>"#), "{chart_xml}");
        assert!(chart_xml.contains(r#"<c:rotY val="35"/>"#), "{chart_xml}");
        assert!(
            chart_xml.contains(r#"<c:perspective val="45"/>"#),
            "{chart_xml}"
        );
        assert!(
            chart_xml.contains(r#"<c:hPercent val="120"/>"#),
            "{chart_xml}"
        );
        assert!(
            chart_xml.contains(r#"<c:depthPercent val="140"/>"#),
            "{chart_xml}"
        );
        assert!(
            chart_xml.contains(r#"<c:gapDepth val="210"/>"#),
            "{chart_xml}"
        );
        assert!(
            chart_xml.contains(r#"<c:shape val="cylinder"/>"#),
            "{chart_xml}"
        );

        let reopened = call_tool_ok(
            &mut runtime,
            "reopen-chart-view-3d",
            "rhwp_open",
            json!({ "path": saved_path }),
        );
        let reopened_id = session_id(&reopened);
        let reopened_controls = call_tool_ok(
            &mut runtime,
            "list-reopened-chart-view-3d",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let reopened_first = reopened_controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing reopened 3D OLE control: {reopened_controls}"));
        let reopened_target = &reopened_first["edit_target"];
        let reopened_data = call_tool_ok(
            &mut runtime,
            "get-reopened-chart-view-3d",
            "rhwp_get_chart_data",
            json!({
                "session_id": reopened_id,
                "section": reopened_target["section"].as_u64().unwrap() as usize,
                "para": reopened_target["para"].as_u64().unwrap() as usize,
                "control": reopened_target["control"].as_u64().unwrap() as usize
            }),
        );
        assert_eq!(reopened_data["view3DRotationX"], 25);
        assert_eq!(reopened_data["view3DRotationY"], 35);
        assert_eq!(reopened_data["view3DPerspective"], 45);
        assert_eq!(reopened_data["view3DRightAngleAxes"], false);
        assert_eq!(reopened_data["view3DHeightPercent"], 120);
        assert_eq!(reopened_data["view3DDepthPercent"], 140);
        assert_eq!(reopened_data["bar3DGapDepth"], 210);
        assert_eq!(reopened_data["bar3DShape"], "cylinder");
    }

    #[test]
    fn hwp_ole_chart_semantic_edit_save_reopen_roundtrip() {
        let mut runtime = runtime();
        let path = "samples/chart/세로막대형/묶은세로막대형.hwp";
        let target = unique_target("hwp-ole-chart-semantic-data", "hwp");
        let open = call_tool_ok(
            &mut runtime,
            "open-hwp-ole-chart-semantic-data",
            "rhwp_open",
            json!({ "path": path }),
        );
        let chart_session_id = session_id(&open);
        let controls = call_tool_ok(
            &mut runtime,
            "list-hwp-ole-chart-semantic-data",
            "rhwp_list_controls",
            json!({
                "session_id": chart_session_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let first = controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing HWP OLE control: {controls}"));
        let target_info = &first["edit_target"];
        let section = target_info["section"].as_u64().unwrap() as usize;
        let para = target_info["para"].as_u64().unwrap() as usize;
        let control = target_info["control"].as_u64().unwrap() as usize;

        let before = call_tool_ok(
            &mut runtime,
            "get-hwp-chart-data-before",
            "rhwp_get_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control
            }),
        );
        assert_eq!(before["chartType"], "Column", "{before}");
        assert_eq!(before["grouping"], "Clustered", "{before}");
        assert_eq!(before["legendPosition"], "Right", "{before}");
        assert_eq!(before["categoryCount"], 4, "{before}");
        assert_eq!(before["seriesCount"], 3, "{before}");

        let edited = call_tool_ok(
            &mut runtime,
            "set-hwp-chart-data",
            "rhwp_set_chart_data",
            json!({
                "session_id": chart_session_id,
                "section": section,
                "para": para,
                "control": control,
                "props": {
                    "grouping": "Stacked",
                    "legendPosition": "Bottom"
                }
            }),
        );
        assert_eq!(edited["chartType"], "Column", "{edited}");
        assert_eq!(edited["grouping"], "Stacked", "{edited}");
        assert_eq!(edited["legendPosition"], "Bottom", "{edited}");

        let save = call_tool_ok(
            &mut runtime,
            "save-hwp-chart-data-edit",
            "rhwp_save",
            json!({
                "session_id": chart_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let saved_bytes = std::fs::read(saved_path).expect("saved chart HWP");
        let parsed = crate::parser::parse_hwp(&saved_bytes).expect("saved HWP reparse");
        let ole_content = parsed
            .bin_data_content
            .iter()
            .find(|content| content.extension.eq_ignore_ascii_case("OLE"))
            .expect("saved HWP OLE BinData");
        let container = crate::parser::ole_container::parse_ole_container(&ole_content.data)
            .expect("saved OLE CFB parse");
        let chart_xml = String::from_utf8(
            container
                .ooxml_chart
                .expect("saved OOXMLChartContents stream"),
        )
        .expect("saved chart XML utf8");
        assert!(
            chart_xml.contains(r#"<c:grouping val="stacked"/>"#),
            "{chart_xml}"
        );
        assert!(
            chart_xml.contains(r#"<c:legendPos val="b"/>"#),
            "{chart_xml}"
        );

        let reopened = call_tool_ok(
            &mut runtime,
            "reopen-hwp-chart-data-edit",
            "rhwp_open",
            json!({ "path": saved_path }),
        );
        let reopened_id = session_id(&reopened);
        let reopened_controls = call_tool_ok(
            &mut runtime,
            "list-reopened-hwp-chart-data-edit",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_id,
                "kind": "Ole",
                "include_nested": true
            }),
        );
        let reopened_first = reopened_controls["controls"]
            .as_array()
            .and_then(|items| items.first())
            .unwrap_or_else(|| panic!("missing reopened HWP OLE control: {reopened_controls}"));
        let reopened_target = &reopened_first["edit_target"];
        let reopened_data = call_tool_ok(
            &mut runtime,
            "get-reopened-hwp-chart-data",
            "rhwp_get_chart_data",
            json!({
                "session_id": reopened_id,
                "section": reopened_target["section"].as_u64().unwrap() as usize,
                "para": reopened_target["para"].as_u64().unwrap() as usize,
                "control": reopened_target["control"].as_u64().unwrap() as usize
            }),
        );
        assert_eq!(reopened_data["chartType"], "Column");
        assert_eq!(reopened_data["grouping"], "Stacked");
        assert_eq!(reopened_data["legendPosition"], "Bottom");
        assert_eq!(reopened_data["categoryCount"], 4);
        assert_eq!(reopened_data["seriesCount"], 3);
    }

