    #[test]
    fn authored_nested_shape_group_caption_hwp_roundtrip() {
        fn assert_nested_group_caption(label: &str, props: &Value, caption_text: &str) {
            assert_eq!(
                props["hasCaption"].as_bool(),
                Some(true),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionText"].as_str(),
                Some(caption_text),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionDirection"].as_str(),
                Some("Top"),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionVertAlign"].as_str(),
                Some("Bottom"),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionWidth"].as_u64(),
                Some(1800),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionSpacing"].as_u64(),
                Some(77),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionMaxWidth"].as_u64(),
                Some(3600),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionIncludeMargin"].as_bool(),
                Some(false),
                "{label}: {props}"
            );
        }

        fn assert_nested_rectangle_caption(label: &str, props: &Value, caption_text: &str) {
            assert_eq!(
                props["hasCaption"].as_bool(),
                Some(true),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionText"].as_str(),
                Some(caption_text),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionDirection"].as_str(),
                Some("Left"),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionVertAlign"].as_str(),
                Some("Center"),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionWidth"].as_u64(),
                Some(1600),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionSpacing"].as_u64(),
                Some(66),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionMaxWidth"].as_u64(),
                Some(3300),
                "{label}: {props}"
            );
            assert_eq!(
                props["captionIncludeMargin"].as_bool(),
                Some(true),
                "{label}: {props}"
            );
        }

        let mut runtime = runtime();
        let target = unique_target("authored-nested-shape-group-caption", "hwp");
        let open = call_tool_ok(
            &mut runtime,
            "open-authored-nested-shape-group-caption",
            "rhwp_open",
            json!({ "path": "samples/group-drawing-02.hwp" }),
        );
        let opened_session_id = session_id(&open);
        let groups = call_tool_ok(
            &mut runtime,
            "list-authored-nested-shape-group-caption",
            "rhwp_list_controls",
            json!({
                "session_id": opened_session_id,
                "kind": "ShapeGroup",
                "include_nested": true,
                "max_items": 20
            }),
        );
        let nested_target = groups["controls"]
            .as_array()
            .expect("groups array")
            .iter()
            .find(|control| {
                control["scope"].as_str() == Some("shape_group_child")
                    && control["summary"]["shape_kind"].as_str() == Some("Group")
                    && control["edit_target"]["group_child_path"] == json!([0])
            })
            .unwrap_or_else(|| panic!("nested ShapeGroup target missing: {groups}"))["edit_target"]
            .as_object()
            .expect("nested target")
            .clone();
        let shapes = call_tool_ok(
            &mut runtime,
            "list-authored-nested-shape-caption-rectangle",
            "rhwp_list_controls",
            json!({
                "session_id": opened_session_id,
                "kind": "Shape",
                "include_nested": true,
                "max_items": 120
            }),
        );
        let rectangle_target = shapes["controls"]
            .as_array()
            .expect("shapes array")
            .iter()
            .find(|control| {
                control["scope"].as_str() == Some("shape_group_child")
                    && control["summary"]["shape_kind"].as_str() == Some("Rectangle")
                    && control["edit_target"]["group_child_path"]
                        .as_array()
                        .map(|path| path.len() == 2)
                        == Some(true)
            })
            .unwrap_or_else(|| panic!("nested Rectangle target missing: {shapes}"))["edit_target"]
            .as_object()
            .expect("rectangle target")
            .clone();

        let caption_text = "MCP 중첩 그룹 캡션";
        let rectangle_caption_text = "MCP 중첩 사각형 캡션";
        let mut set_args = nested_target.clone();
        set_args.insert("session_id".to_string(), json!(opened_session_id));
        set_args.insert(
            "props".to_string(),
            json!({
                "has_caption": true,
                "caption_text": caption_text,
                "caption_direction": "Top",
                "caption_vert_align": "Bottom",
                "caption_width": 1800,
                "caption_spacing": 77,
                "caption_max_width": 3600,
                "caption_include_margin": false
            }),
        );
        let set = call_tool_ok(
            &mut runtime,
            "set-authored-nested-shape-group-caption",
            "rhwp_set_shape_properties",
            Value::Object(set_args),
        );
        assert_eq!(set["ok"], true, "{set}");

        let mut set_rectangle_args = rectangle_target.clone();
        set_rectangle_args.insert("session_id".to_string(), json!(opened_session_id));
        set_rectangle_args.insert(
            "props".to_string(),
            json!({
                "has_caption": true,
                "caption_text": rectangle_caption_text,
                "caption_direction": "Left",
                "caption_vert_align": "Center",
                "caption_width": 1600,
                "caption_spacing": 66,
                "caption_max_width": 3300,
                "caption_include_margin": true
            }),
        );
        let set_rectangle = call_tool_ok(
            &mut runtime,
            "set-authored-nested-rectangle-caption",
            "rhwp_set_shape_properties",
            Value::Object(set_rectangle_args),
        );
        assert_eq!(set_rectangle["ok"], true, "{set_rectangle}");

        let mut get_args = nested_target.clone();
        get_args.insert("session_id".to_string(), json!(opened_session_id));
        let edited = call_tool_ok(
            &mut runtime,
            "get-authored-nested-shape-group-caption",
            "rhwp_get_shape_properties",
            Value::Object(get_args),
        );
        assert_nested_group_caption("edited", &edited, caption_text);
        let mut get_rectangle_args = rectangle_target.clone();
        get_rectangle_args.insert("session_id".to_string(), json!(opened_session_id));
        let edited_rectangle = call_tool_ok(
            &mut runtime,
            "get-authored-nested-rectangle-caption",
            "rhwp_get_shape_properties",
            Value::Object(get_rectangle_args),
        );
        assert_nested_rectangle_caption(
            "edited rectangle",
            &edited_rectangle,
            rectangle_caption_text,
        );

        let save = call_tool_ok(
            &mut runtime,
            "save-authored-nested-shape-group-caption",
            "rhwp_save",
            json!({
                "session_id": opened_session_id,
                "path": target,
                "format": "hwp",
                "overwrite": true
            }),
        );
        let saved_path = save["write"]["path"].as_str().expect("saved path");
        let reopened = call_tool_ok(
            &mut runtime,
            "reopen-authored-nested-shape-group-caption",
            "rhwp_open",
            json!({ "path": saved_path }),
        );
        let reopened_session_id = session_id(&reopened);
        let reopened_groups = call_tool_ok(
            &mut runtime,
            "list-reopened-authored-nested-shape-group-caption",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_session_id,
                "kind": "ShapeGroup",
                "include_nested": true,
                "max_items": 20
            }),
        );
        let reopened_target = reopened_groups["controls"]
            .as_array()
            .expect("reopened groups array")
            .iter()
            .find(|control| {
                control["scope"].as_str() == Some("shape_group_child")
                    && control["summary"]["shape_kind"].as_str() == Some("Group")
                    && control["edit_target"]["group_child_path"] == json!([0])
            })
            .unwrap_or_else(|| {
                panic!("reopened nested ShapeGroup target missing: {reopened_groups}")
            })["edit_target"]
            .as_object()
            .expect("reopened nested target")
            .clone();
        let reopened_shapes = call_tool_ok(
            &mut runtime,
            "list-reopened-authored-nested-rectangle-caption",
            "rhwp_list_controls",
            json!({
                "session_id": reopened_session_id,
                "kind": "Shape",
                "include_nested": true,
                "max_items": 120
            }),
        );
        let reopened_rectangle_target = reopened_shapes["controls"]
            .as_array()
            .expect("reopened shapes array")
            .iter()
            .find(|control| {
                control["scope"].as_str() == Some("shape_group_child")
                    && control["summary"]["shape_kind"].as_str() == Some("Rectangle")
                    && control["edit_target"]["group_child_path"]
                        == json!(rectangle_target["group_child_path"])
            })
            .unwrap_or_else(|| {
                panic!("reopened nested Rectangle target missing: {reopened_shapes}")
            })["edit_target"]
            .as_object()
            .expect("reopened rectangle target")
            .clone();

        let mut reopened_args = reopened_target;
        reopened_args.insert("session_id".to_string(), json!(reopened_session_id));
        let reopened_props = call_tool_ok(
            &mut runtime,
            "get-reopened-authored-nested-shape-group-caption",
            "rhwp_get_shape_properties",
            Value::Object(reopened_args),
        );
        assert_nested_group_caption("reopened", &reopened_props, caption_text);
        let mut reopened_rectangle_args = reopened_rectangle_target;
        reopened_rectangle_args.insert("session_id".to_string(), json!(reopened_session_id));
        let reopened_rectangle_props = call_tool_ok(
            &mut runtime,
            "get-reopened-authored-nested-rectangle-caption",
            "rhwp_get_shape_properties",
            Value::Object(reopened_rectangle_args),
        );
        assert_nested_rectangle_caption(
            "reopened rectangle",
            &reopened_rectangle_props,
            rectangle_caption_text,
        );
    }

