        insert_args.insert("width".to_string(), json!(3456));
        insert_args.insert("height".to_string(), json!(1234));
        insert_args.insert("horizontal_offset".to_string(), json!(2222));
        insert_args.insert("vertical_offset".to_string(), json!(1111));
