    #[test]
    fn table_cell_edit_formula_and_export_roundtrip() {
        let mut runtime = runtime();
        let new_doc = call_tool_ok(&mut runtime, "new-table", "rhwp_new", json!({}));
        let session_id = session_id(&new_doc);
        let table = call_tool_ok(
            &mut runtime,
            "create-table",
            "rhwp_create_table",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "rows": 2,
                "cols": 2
            }),
        );
        let para = table["paraIdx"].as_u64().expect("table para") as usize;
        let control = table["controlIdx"].as_u64().expect("table control") as usize;

        let dims = call_tool_ok(
            &mut runtime,
            "table-dims",
            "rhwp_get_table_dimensions",
            json!({ "session_id": session_id, "section": 0, "para": para, "control": control }),
        );
        assert_eq!(dims["rowCount"], 2);
        assert_eq!(dims["colCount"], 2);

        let before_props = call_tool_ok(
            &mut runtime,
            "table-properties-before",
            "rhwp_get_table_properties",
            json!({ "session_id": session_id, "section": 0, "para": para, "control": control }),
        );
        assert!(before_props["tableWidth"].as_u64().unwrap_or(0) > 0);

        let set_props = call_tool_ok(
            &mut runtime,
            "set-table-properties-snake-case",
            "rhwp_set_table_properties",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "props": {
                    "cell_spacing": 17,
                    "padding_left": 21,
                    "padding_right": 22,
                    "padding_top": 23,
                    "padding_bottom": 24,
                    "page_break": 1,
                    "repeat_header": true,
                    "treat_as_char": true,
                    "text_wrap": "TopAndBottom",
                    "vert_rel_to": "Page",
                    "horz_rel_to": "Page",
                    "vert_align": "Center",
                    "horz_align": "Center",
                    "vert_offset": 31,
                    "horz_offset": 32,
                    "restrict_in_page": true,
                    "allow_overlap": true,
                    "keep_with_anchor": true
                }
            }),
        );
        assert_eq!(set_props["ok"], true);

        let after_props = call_tool_ok(
            &mut runtime,
            "table-properties-after",
            "rhwp_get_table_properties",
            json!({ "session_id": session_id, "section": 0, "para": para, "control": control }),
        );
        assert_eq!(after_props["cellSpacing"], 17, "{after_props}");
        assert_eq!(after_props["paddingLeft"], 21, "{after_props}");
        assert_eq!(after_props["paddingRight"], 22, "{after_props}");
        assert_eq!(after_props["paddingTop"], 23, "{after_props}");
        assert_eq!(after_props["paddingBottom"], 24, "{after_props}");
        assert_eq!(after_props["pageBreak"], 1, "{after_props}");
        assert_eq!(after_props["repeatHeader"], true, "{after_props}");
        assert_eq!(after_props["treatAsChar"], true, "{after_props}");
        assert_eq!(after_props["textWrap"], "TopAndBottom", "{after_props}");
        assert_eq!(after_props["vertRelTo"], "Page", "{after_props}");
        assert_eq!(after_props["horzRelTo"], "Page", "{after_props}");
        assert_eq!(after_props["vertAlign"], "Center", "{after_props}");
        assert_eq!(after_props["horzAlign"], "Center", "{after_props}");
        assert_eq!(after_props["vertOffset"], 31, "{after_props}");
        assert_eq!(after_props["horzOffset"], 32, "{after_props}");
        assert_eq!(after_props["restrictInPage"], true, "{after_props}");
        assert_eq!(after_props["allowOverlap"], true, "{after_props}");
        assert_eq!(after_props["keepWithAnchor"], true, "{after_props}");

        for (id, row, col, text) in [
            ("set-a1", 0, 0, "10"),
            ("set-b1", 0, 1, "20"),
            ("set-a2", 1, 0, "5"),
        ] {
            call_tool_ok(
                &mut runtime,
                id,
                "rhwp_set_cell_text",
                json!({
                    "session_id": session_id,
                    "section": 0,
                    "para": para,
                    "control": control,
                    "row": row,
                    "col": col,
                    "text": text
                }),
            );
        }

        let cell = call_tool_ok(
            &mut runtime,
            "get-b1",
            "rhwp_get_cell_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "row": 0,
                "col": 1
            }),
        );
        assert_eq!(cell["text"], "20");

        let formula = call_tool_ok(
            &mut runtime,
            "formula",
            "rhwp_evaluate_table_formula",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "target_row": 1,
                "target_col": 1,
                "formula": "=SUM(A1:B1)",
                "write_result": true
            }),
        );
        assert_eq!(formula["ok"], true);
        assert_eq!(formula["result"].as_f64().expect("formula result"), 30.0);

        let result_cell = call_tool_ok(
            &mut runtime,
            "get-b2",
            "rhwp_get_cell_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "row": 1,
                "col": 1
            }),
        );
        assert_eq!(result_cell["text"], "30");

        let export = call_tool_ok(
            &mut runtime,
            "export-table",
            "rhwp_export_bytes",
            json!({ "session_id": session_id, "format": "hwpx" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("table HWPX reparses");
        assert!(reparsed.page_count() >= 1);
        let reparsed_props = reparsed
            .get_table_properties_native(0, para, control)
            .expect("reparsed table properties");
        let reparsed_props: Value =
            serde_json::from_str(&reparsed_props).expect("reparsed table props json");
        assert_eq!(reparsed_props["cellSpacing"], 17, "{reparsed_props}");
        assert_eq!(reparsed_props["paddingLeft"], 21, "{reparsed_props}");
        assert_eq!(reparsed_props["repeatHeader"], true, "{reparsed_props}");
        assert_eq!(reparsed_props["treatAsChar"], true, "{reparsed_props}");
        assert_eq!(
            reparsed_props["textWrap"], "TopAndBottom",
            "{reparsed_props}"
        );
        assert_eq!(reparsed_props["vertRelTo"], "Page", "{reparsed_props}");
        assert_eq!(reparsed_props["horzRelTo"], "Page", "{reparsed_props}");
        assert_eq!(reparsed_props["vertAlign"], "Center", "{reparsed_props}");
        assert_eq!(reparsed_props["horzAlign"], "Center", "{reparsed_props}");
    }

    #[test]
    fn replace_text_query_targets_table_cell_through_mcp_tool_call() {
        let mut runtime = runtime();
        let new_doc = call_tool_ok(
            &mut runtime,
            "new-query-replace-cell",
            "rhwp_new",
            json!({}),
        );
        let session_id = session_id(&new_doc);
        let table = call_tool_ok(
            &mut runtime,
            "create-query-replace-cell-table",
            "rhwp_create_table",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "rows": 1,
                "cols": 1
            }),
        );
        let para = table["paraIdx"].as_u64().expect("table para") as usize;
        let control = table["controlIdx"].as_u64().expect("table control") as usize;
        let needle = "MCP single query cell needle";
        let replacement = "MCP single query cell replaced";

        call_tool_ok(
            &mut runtime,
            "set-query-replace-cell",
            "rhwp_set_cell_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "row": 0,
                "col": 0,
                "text": needle
            }),
        );

        let replaced = call_tool_ok(
            &mut runtime,
            "replace-query-cell",
            "rhwp_replace_text",
            json!({
                "session_id": session_id,
                "query": needle,
                "new_text": replacement,
                "case_sensitive": true
            }),
        );
        assert_eq!(replaced["ok"], true, "{replaced}");
        assert!(
            replaced["cellContext"].is_object(),
            "query-based replacement should report table-cell context: {replaced}"
        );

        let cell = call_tool_ok(
            &mut runtime,
            "get-query-replaced-cell",
            "rhwp_get_cell_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "control": control,
                "row": 0,
                "col": 0
            }),
        );
        assert_eq!(cell["text"], replacement);

        let old_hits = call_tool_ok(
            &mut runtime,
            "search-query-replace-old",
            "rhwp_search",
            json!({
                "session_id": session_id,
                "query": needle,
                "include_cells": true
            }),
        );
        assert_eq!(
            old_hits.as_array().expect("old hits").len(),
            0,
            "{old_hits}"
        );
        let new_hits = call_tool_ok(
            &mut runtime,
            "search-query-replace-new",
            "rhwp_search",
            json!({
                "session_id": session_id,
                "query": replacement,
                "include_cells": true
            }),
        );
        let new_hits = new_hits.as_array().expect("new hits");
        assert_eq!(new_hits.len(), 1, "{new_hits:?}");
        assert!(
            new_hits[0]["cellContext"].is_object(),
            "search should also expose table-cell context: {new_hits:?}"
        );

        let export = call_tool_ok(
            &mut runtime,
            "export-query-replaced-cell",
            "rhwp_export_bytes",
            json!({ "session_id": session_id, "format": "hwp" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("query-replaced HWP reparses");
        assert!(
            document_contains_table_cell_text(&reparsed, replacement),
            "query replacement should survive HWP export/reparse"
        );
    }

    #[test]
    fn replace_text_query_targets_shape_text_box_through_mcp_tool_call() {
        let mut runtime = runtime();
        let new_doc = call_tool_ok(
            &mut runtime,
            "new-query-replace-textbox",
            "rhwp_new",
            json!({}),
        );
        let session_id = session_id(&new_doc);
        let textbox = call_tool_ok(
            &mut runtime,
            "insert-query-replace-textbox",
            "rhwp_insert_shape",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "shape_type": "textbox",
                "width": 7200,
                "height": 2400,
                "horizontal_offset": 1000,
                "vertical_offset": 1000,
                "text_wrap": "InFrontOfText"
            }),
        );
        assert_eq!(textbox["ok"], true, "textbox insert failed: {textbox}");
        let para = textbox["paraIdx"].as_u64().expect("textbox para") as usize;
        let control = textbox["controlIdx"].as_u64().expect("textbox control") as usize;
        let text_box_path = json!([[control, 0, 0]]);
        let needle = "MCP single query textbox needle";
        let replacement = "MCP single query textbox replaced";

        call_tool_ok(
            &mut runtime,
            "set-query-replace-textbox",
            "rhwp_set_cell_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": para,
                "cell_path": text_box_path,
                "text": needle
            }),
        );

        let replaced = call_tool_ok(
            &mut runtime,
            "replace-query-textbox",
            "rhwp_replace_text",
            json!({
                "session_id": session_id,
                "query": needle,
                "new_text": replacement,
                "case_sensitive": true
            }),
        );
        assert_eq!(replaced["ok"], true, "{replaced}");
        assert_eq!(replaced["cellContext"]["parentPara"], para, "{replaced}");
        assert_eq!(replaced["cellContext"]["ctrlIdx"], control, "{replaced}");

        let hits = call_tool_ok(
            &mut runtime,
            "search-query-replace-textbox-new",
            "rhwp_search",
            json!({
                "session_id": session_id,
                "query": replacement,
                "include_cells": true
            }),
        );
        let hits = hits.as_array().expect("textbox hits");
        assert_eq!(hits.len(), 1, "{hits:?}");
        assert!(
            hits[0]["cellContext"].is_object(),
            "search should expose text-box cell context: {hits:?}"
        );

        let export = call_tool_ok(
            &mut runtime,
            "export-query-replaced-textbox",
            "rhwp_export_bytes",
            json!({ "session_id": session_id, "format": "hwpx" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("query-replaced HWPX reparses");
        let reparsed_hits: Value = serde_json::from_str(
            &reparsed
                .search_all_text_native(replacement, true, true)
                .expect("reparsed text-box search succeeds"),
        )
        .expect("reparsed text-box search JSON");
        let reparsed_hits = reparsed_hits.as_array().expect("reparsed text-box hits");
        assert_eq!(reparsed_hits.len(), 1, "{reparsed_hits:?}");
        assert!(
            reparsed_hits[0]["cellContext"].is_object(),
            "query replacement should survive HWPX export/reparse"
        );
    }

    #[test]
    fn nested_table_cell_path_edit_and_export_roundtrip() {
        let mut runtime = runtime();
        let open = call_tool_ok(
            &mut runtime,
            "open-inner-table",
            "rhwp_open",
            json!({ "path": "samples/inner-table-01.hwp" }),
        );
        let session_id = session_id(&open);

        let controls = call_tool_ok(
            &mut runtime,
            "list-inner-tables",
            "rhwp_list_controls",
            json!({
                "session_id": session_id,
                "kind": "Table",
                "include_nested": true,
                "max_items": 20
            }),
        );
        let nested_table = controls["controls"]
            .as_array()
            .expect("controls")
            .iter()
            .find(|control| control["kind"] == "Table" && control["scope"] == "table_cell")
            .unwrap_or_else(|| panic!("expected nested table control: {controls}"));
        let edit_target = nested_table["edit_target"]
            .as_object()
            .expect("edit target");
        let mut cell_path = edit_target["cell_path"]
            .as_array()
            .expect("nested table cell path prefix")
            .clone();
        cell_path.push(json!([
            edit_target["inner_control"]
                .as_u64()
                .expect("nested table inner control"),
            0,
            0
        ]));
        let cell_path = Value::Array(cell_path);
        let section = edit_target["section"].as_u64().expect("section") as usize;
        let para = edit_target["para"].as_u64().expect("para") as usize;

        let nested_props_before = call_tool_ok(
            &mut runtime,
            "get-nested-table-properties-before",
            "rhwp_get_table_properties",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path.clone()
            }),
        );
        assert!(
            nested_props_before["tableWidth"].as_u64().unwrap_or(0) > 0,
            "{nested_props_before}"
        );

        let nested_props_set = call_tool_ok(
            &mut runtime,
            "set-nested-table-properties",
            "rhwp_set_table_properties",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path.clone(),
                "props": {
                    "cell_spacing": 19,
                    "padding_left": 31,
                    "padding_right": 32,
                    "repeat_header": true
                }
            }),
        );
        assert_eq!(nested_props_set["ok"], true, "{nested_props_set}");

        let nested_props_after = call_tool_ok(
            &mut runtime,
            "get-nested-table-properties-after",
            "rhwp_get_table_properties",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path.clone()
            }),
        );
        assert_eq!(
            nested_props_after["cellSpacing"], 19,
            "{nested_props_after}"
        );
        assert_eq!(
            nested_props_after["paddingLeft"], 31,
            "{nested_props_after}"
        );
        assert_eq!(
            nested_props_after["paddingRight"], 32,
            "{nested_props_after}"
        );
        assert_eq!(
            nested_props_after["repeatHeader"], true,
            "{nested_props_after}"
        );

        let original = call_tool_ok(
            &mut runtime,
            "get-nested-cell-before",
            "rhwp_get_cell_text",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path
            }),
        );
        assert_eq!(original["text"], "요구사항 번호");

        let updated_text = "MCP nested table edit";
        let set = call_tool_ok(
            &mut runtime,
            "set-nested-cell",
            "rhwp_set_cell_text",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path,
                "text": updated_text
            }),
        );
        assert_eq!(set["ok"], true);

        let edited = call_tool_ok(
            &mut runtime,
            "get-nested-cell-after",
            "rhwp_get_cell_text",
            json!({
                "session_id": session_id,
                "section": section,
                "para": para,
                "cell_path": cell_path
            }),
        );
        assert_eq!(edited["text"], updated_text);

        let export = call_tool_ok(
            &mut runtime,
            "export-inner-table",
            "rhwp_export_bytes",
            json!({ "session_id": session_id, "format": "hwp" }),
        );
        let bytes = decode_export(&export);
        let reparsed = DocumentCore::from_bytes(&bytes).expect("nested table HWP reparses");
        assert!(
            document_contains_table_cell_text(&reparsed, updated_text),
            "reparsed nested table text not found"
        );
        let reparsed_path: Vec<(usize, usize, usize)> = cell_path
            .as_array()
            .expect("cell_path array")
            .iter()
            .map(|entry| {
                let parts = entry.as_array().expect("cell_path tuple");
                (
                    parts[0].as_u64().expect("control") as usize,
                    parts[1].as_u64().expect("cell") as usize,
                    parts[2].as_u64().expect("para") as usize,
                )
            })
            .collect();
        let reparsed_props = reparsed
            .get_table_properties_by_cell_path_native(section, para, &reparsed_path)
            .expect("reparsed nested table properties");
        let reparsed_props: Value =
            serde_json::from_str(&reparsed_props).expect("reparsed nested props json");
        assert_eq!(reparsed_props["cellSpacing"], 19, "{reparsed_props}");
        assert_eq!(reparsed_props["paddingLeft"], 31, "{reparsed_props}");
        assert_eq!(reparsed_props["repeatHeader"], true, "{reparsed_props}");

        let diff = call_tool_ok(
            &mut runtime,
            "compare-inner-table-records",
            "rhwp_compare_hwp_records",
            json!({
                "session_id": session_id,
                "other_path": "samples/inner-table-01.hwp",
                "max_diffs": 8
            }),
        );
        assert_eq!(
            diff["equal"], false,
            "record diff should detect edit: {diff}"
        );
        assert!(diff["difference_count"].as_u64().unwrap_or(0) > 0);
    }

