    #[test]
    fn compare_render_png_self_returns_zero_diff() {
        let mut runtime = runtime();
        let new_doc = call_tool_ok(&mut runtime, "new-png-compare", "rhwp_new", json!({}));
        let session_id = session_id(&new_doc);
        call_tool_ok(
            &mut runtime,
            "insert-png-compare-text",
            "rhwp_insert_text",
            json!({
                "session_id": session_id,
                "section": 0,
                "para": 0,
                "char_offset": 0,
                "text": "MCP PNG compare smoke"
            }),
        );

        let diff = call_tool_ok(
            &mut runtime,
            "compare-png",
            "rhwp_compare_render_png",
            json!({
                "session_id": session_id,
                "other_session_id": session_id,
                "page": 0
            }),
        );
        assert_eq!(diff["renderer"].as_str(), Some("svg-resvg"));
        assert_eq!(diff["same_size"].as_bool(), Some(true));
        assert_eq!(diff["changed_pixels"].as_u64(), Some(0));
        assert_eq!(diff["changed_percent"].as_f64(), Some(0.0));
        assert_eq!(diff["mean_abs_diff"].as_f64(), Some(0.0));
        assert!(diff["pixel_count"].as_u64().unwrap_or(0) > 0);
        assert_eq!(diff["layout_overflow_count"].as_u64(), Some(0));
        assert!(diff["layout_overflows"].as_array().is_some());
    }

    #[test]
    fn compare_style_signature_self_returns_equal() {
        let mut runtime = runtime();
        let new_doc = call_tool_ok(&mut runtime, "new-style-signature", "rhwp_new", json!({}));
        let session_id = session_id(&new_doc);
        call_tool_ok(
            &mut runtime,
            "create-style-signature-style",
            "rhwp_create_style",
            json!({
                "session_id": session_id,
                "name": "MCP style signature",
                "english_name": "MCP Style Signature",
                "char_format": {
                    "bold": true,
                    "font_size": 1200
                },
                "para_format": {
                    "alignment": "center",
                    "line_spacing": 180
                }
            }),
        );
        let signature = call_tool_ok(
            &mut runtime,
            "style-signature",
            "rhwp_style_signature",
            json!({ "session_id": session_id }),
        );
        assert_eq!(
            signature["signature_version"].as_str(),
            Some("rhwp-style-signature-v1")
        );
        assert!(signature["style_list_count"].as_u64().unwrap_or(0) >= 2);
        assert!(signature["template_style_count"].as_u64().unwrap_or(0) >= 2);
        assert!(signature["style_list_hash"].as_str().unwrap_or("").len() >= 32);

        let diff = call_tool_ok(
            &mut runtime,
            "compare-style-signature",
            "rhwp_compare_style_signature",
            json!({
                "session_id": session_id,
                "other_session_id": session_id
            }),
        );
        assert_eq!(diff["equal"].as_bool(), Some(true));
        assert_eq!(diff["difference_count"].as_u64(), Some(0));
        assert!(diff["differences"].as_array().unwrap().is_empty());
        assert_eq!(
            diff["left"]["style_list_hash"],
            diff["right"]["style_list_hash"]
        );
        assert_eq!(
            diff["left"]["style_ref_hash"],
            diff["right"]["style_ref_hash"]
        );
    }

